// 2026 Daily Gospel Readings — Roman Catholic Liturgical Calendar
// Liturgical Year C (Sundays) | Year II (Weekdays)
// Lent begins: Feb 18, 2026 (Ash Wednesday)
// Easter: April 5, 2026 | Pentecost: May 24, 2026
// Advent 2026 begins: Nov 29, 2026

const GOSPEL_DATA = {

// ==================== JANUARY ====================
"01-01": { season: "Solemnity", title: "From the Gospel according to Luke 2:16-21", ref: "Luke 2:16-21", verse: "The shepherds went in haste to Bethlehem and found Mary and Joseph, and the infant lying in the manger. When they saw this, they made known the message that had been told them about this child. All who heard it were amazed by what had been told them by the shepherds. And Mary kept all these things, reflecting on them in her heart. Then the shepherds returned, glorifying and praising God for all they had heard and seen, just as it had been told to them. When eight days were completed for his circumcision, he was named Jesus, the name given him by the angel before he was conceived in the womb." },
"01-02": { season: "Christmas", title: "Friday after January 1", ref: "John 1:19-28", verse: "I am the voice of one crying out in the desert, 'Make straight the way of the Lord.'", summary: "John the Baptist testifies before the priests and Levites. He denies being the Messiah, Elijah, or the Prophet — he is the voice crying in the wilderness." },
"01-03": { season: "Christmas", title: "Saturday after January 1", ref: "John 1:29-34", verse: "Behold, the Lamb of God, who takes away the sin of the world!", summary: "John the Baptist points out Jesus as the Lamb of God. He testifies to seeing the Spirit descend like a dove and remaining on Jesus." },
"01-04": { season: "Christmas", title: "2nd Sunday after Christmas / Epiphany Vigil", ref: "John 1:1-18", verse: "The Word became flesh and made his dwelling among us.", summary: "The Prologue of John: In the beginning was the Word. All things came to be through him. He came to his own but they did not accept him. To those who accept him he gives power to become children of God." },
"01-05": { season: "Christmas", title: "Monday — 2nd Week of Christmas", ref: "Mark 1:7-11", verse: "You are my beloved Son; with you I am well pleased.", summary: "John the Baptist preaches about the one mightier than he who will baptize with the Holy Spirit. Jesus comes from Nazareth and is baptized in the Jordan. The Spirit descends and the Father's voice is heard." },
"01-06": { season: "Solemnity", title: "Epiphany of the Lord", ref: "Matthew 2:1-12", verse: "We saw his star at its rising and have come to do him homage.", summary: "The Magi from the East follow the star to Jerusalem, then Bethlehem. They find the child with Mary and offer him gifts of gold, frankincense, and myrrh. Warned in a dream, they return home by another route." },
"01-07": { season: "Christmas", title: "Wednesday after Epiphany / St. Raymond of Penyafort", ref: "John 2:1-11", verse: "His mother said to the servers, 'Do whatever he tells you.'", summary: "The Wedding at Cana: Jesus performs his first sign, changing water into wine at Mary's request. This revelation of his glory leads his disciples to believe in him." },
"01-08": { season: "Christmas", title: "Thursday after Epiphany", ref: "Luke 4:14-22", verse: "Today this Scripture passage is fulfilled in your hearing.", summary: "Jesus returns to Galilee in the power of the Spirit. In the synagogue at Nazareth he reads from Isaiah: 'The Spirit of the Lord is upon me.' He declares the Scripture fulfilled." },
"01-09": { season: "Christmas", title: "Friday after Epiphany", ref: "Luke 5:12-16", verse: "Lord, if you wish, you can make me clean.", summary: "A man covered with leprosy falls before Jesus and begs to be healed. Jesus stretches out his hand, touches him and says: 'I do will it. Be made clean.' The leprosy leaves immediately." },
"01-10": { season: "Christmas", title: "Saturday after Epiphany", ref: "John 3:22-30", verse: "He must increase; I must decrease.", summary: "John the Baptist's disciples complain that Jesus is baptizing more people. John rejoices as the bridegroom's friend, fully content in the role of witness. His joy is complete in pointing to Christ." },
"01-11": { season: "Ordinary Time", title: "Baptism of the Lord", ref: "Luke 3:15-16, 21-22", verse: "You are my beloved Son; with you I am well pleased.", summary: "John clarifies he is not the Messiah. After all the people were baptized, Jesus was also baptized and praying — heaven opened, the Holy Spirit descended in bodily form as a dove, and the Father's voice was heard." },
"01-12": { season: "Ordinary Time", title: "Monday — 1st Week of Ordinary Time", ref: "Mark 1:14-20", verse: "Come after me, and I will make you fishers of men.", summary: "Jesus proclaims the Kingdom of God is at hand. By the Sea of Galilee he calls Simon, Andrew, James, and John — and they immediately leave their nets to follow him." },
"01-13": { season: "Ordinary Time", title: "Tuesday — 1st Week / St. Hilary", ref: "Mark 1:21-28", verse: "What is this? A new teaching with authority!", summary: "Jesus teaches in the Capernaum synagogue with authority. He casts out an unclean spirit, commanding it to be quiet and come out. All are amazed at his new teaching with power." },
"01-14": { season: "Ordinary Time", title: "Wednesday — 1st Week of Ordinary Time", ref: "Mark 1:29-39", verse: "He cured many who were sick with various diseases.", summary: "Jesus heals Simon's mother-in-law, then cures many sick at evening. Early in the morning he goes to a deserted place to pray. He declares he must preach in other towns — that is why he came." },
"01-15": { season: "Ordinary Time", title: "Thursday — 1st Week of Ordinary Time", ref: "Mark 1:40-45", verse: "If you wish, you can make me clean.", summary: "A leper approaches Jesus and is cured. Jesus instructs him to say nothing to anyone, but to show himself to the priest. The man however spreads the news widely." },
"01-16": { season: "Ordinary Time", title: "Friday — 1st Week of Ordinary Time", ref: "Mark 2:1-12", verse: "Child, your sins are forgiven.", summary: "Four men bring a paralytic to Jesus through a hole in the roof. Jesus forgives the man's sins, scandalizing the scribes. He then heals the paralytic to show he has authority to forgive sins." },
"01-17": { season: "Ordinary Time", title: "Saturday — 1st Week / St. Anthony, Abbot", ref: "Mark 2:13-17", verse: "I did not come to call the righteous but sinners.", summary: "Jesus calls Levi the tax collector, who immediately follows him. Jesus dines with tax collectors and sinners, answering critics: the healthy need no physician — he came for sinners." },
"01-18": { season: "Ordinary Time", title: "2nd Sunday of Ordinary Time — Year C", ref: "John 2:1-11", verse: "Do whatever he tells you.", summary: "The Wedding at Cana: Mary intercedes for the couple. Jesus changes six stone water jars into the finest wine. This first sign manifests his glory and leads his disciples to believe in him." },
"01-19": { season: "Ordinary Time", title: "Monday — 2nd Week of Ordinary Time", ref: "Mark 2:18-22", verse: "No one pours new wine into old wineskins.", summary: "Asked about fasting, Jesus says his disciples cannot fast while the bridegroom is with them. The time will come when the bridegroom is taken. New cloth, new wineskins — the new age has arrived." },
"01-20": { season: "Ordinary Time", title: "Tuesday — 2nd Week / St. Fabian; St. Sebastian", ref: "Mark 2:23-28", verse: "The Son of Man is lord even of the sabbath.", summary: "The Pharisees criticize the disciples for picking grain on the Sabbath. Jesus cites David eating the showbread. The Sabbath was made for man, not man for the Sabbath." },
"01-21": { season: "Ordinary Time", title: "Wednesday — 2nd Week / St. Agnes", ref: "Mark 3:1-6", verse: "Is it lawful to do good on the sabbath rather than to do evil?", summary: "In the synagogue, Jesus heals a man with a withered hand on the Sabbath, despite the Pharisees watching. He is grieved by their hardness of heart. The Pharisees immediately plot to kill him." },
"01-22": { season: "Ordinary Time", title: "Thursday — 2nd Week of Ordinary Time", ref: "Mark 3:7-12", verse: "Whenever unclean spirits saw him they would fall down before him.", summary: "Large crowds from Galilee and beyond press around Jesus at the sea. He has a boat ready. He cures many and the unclean spirits fall before him and cry out that he is the Son of God." },
"01-23": { season: "Ordinary Time", title: "Friday — 2nd Week of Ordinary Time", ref: "Mark 3:13-19", verse: "He appointed twelve, whom he also named Apostles.", summary: "Jesus goes up the mountain and calls those he himself chose. He appoints the Twelve — listing each by name — to be with him, to preach, and to drive out demons." },
"01-24": { season: "Ordinary Time", title: "Saturday — 2nd Week / St. Francis de Sales", ref: "Mark 3:20-21", verse: "He is out of his mind.", summary: "Jesus returns home and a crowd gathers so large that he cannot eat. His relatives hear this and set out to seize him, saying he is out of his mind." },
"01-25": { season: "Feast", title: "Conversion of St. Paul the Apostle", ref: "Mark 16:15-18", verse: "Go into the whole world and proclaim the Gospel to every creature.", summary: "The Risen Christ commissions the disciples to preach the Gospel to all creation. Those who believe and are baptized will be saved. These signs will accompany believers: they will drive out demons and speak new languages." },
"01-26": { season: "Memorial", title: "Sts. Timothy and Titus", ref: "Mark 4:1-20", verse: "Whoever has ears ought to hear.", summary: "The Parable of the Sower: seed falls on the path, rocky ground, thorns, and good soil. Jesus explains the parable: the seed is the Word of God. The good soil produces thirty, sixty, and a hundredfold." },
"01-27": { season: "Ordinary Time", title: "Tuesday — 3rd Week of Ordinary Time", ref: "Mark 3:31-35", verse: "Whoever does the will of God is my brother and sister and mother.", summary: "Jesus' mother and brothers arrive asking for him. Jesus looks around and says those seated with him are his family — whoever does the will of God." },
"01-28": { season: "Memorial", title: "St. Thomas Aquinas", ref: "Mark 4:21-25", verse: "Is a lamp brought in to be placed under a bushel basket?", summary: "Jesus speaks of the lamp placed on a lampstand. Nothing is hidden that will not be made visible. Pay attention to what you hear — to whoever has, more will be given." },
"01-29": { season: "Ordinary Time", title: "Thursday — 3rd Week of Ordinary Time", ref: "Mark 4:26-34", verse: "This is how it is with the Kingdom of God.", summary: "The parable of the seed that grows by itself and the mustard seed — the smallest of seeds that becomes the largest of plants. Jesus uses parables to speak to the crowds." },
"01-30": { season: "Ordinary Time", title: "Friday — 3rd Week of Ordinary Time", ref: "Mark 4:35-41", verse: "Who then is this whom even wind and sea obey?", summary: "In a storm on the sea, Jesus rebukes the wind and says to the sea: 'Quiet! Be still!' The disciples are terrified and ask who this is that even wind and sea obey him." },
"01-31": { season: "Memorial", title: "St. John Bosco", ref: "Mark 5:1-20", verse: "Go home to your family and announce to them all that the Lord in his mercy has done for you.", summary: "Jesus casts a legion of demons out of a man in the Gerasene territory. The man is healed and desires to follow Jesus. Jesus sends him home to witness to his family." },

// ==================== FEBRUARY ====================
"02-01": { season: "Ordinary Time", title: "4th Sunday of Ordinary Time — Year C", ref: "Luke 4:21-30", verse: "No prophet is accepted in his own native place.", summary: "Jesus in Nazareth declares the Scripture fulfilled. When he mentions Elijah and Elisha helping Gentiles, the crowd is furious and tries to throw him off a cliff. He passes through their midst and goes away." },
"02-02": { season: "Feast", title: "Presentation of the Lord (Candlemas)", ref: "Luke 2:22-40", verse: "Now, Master, you may let your servant go in peace, for my eyes have seen your salvation.", summary: "Mary and Joseph present Jesus in the Temple. Simeon takes the child and prays the Nunc Dimittis. He prophecies a sword will pierce Mary's soul. Anna gives thanks and speaks of the child to all." },
"02-03": { season: "Memorial", title: "St. Blase; St. Ansgar", ref: "Mark 6:1-6", verse: "A prophet is not without honor except in his native place.", summary: "Jesus returns to Nazareth. People are astonished yet take offense at him. Jesus is amazed at their lack of faith and is unable to do many mighty deeds there." },
"02-04": { season: "Ordinary Time", title: "Wednesday — 4th Week of Ordinary Time", ref: "Mark 6:7-13", verse: "He instructed them to take nothing for the journey.", summary: "Jesus sends out the Twelve two by two with authority over unclean spirits, instructing them to take nothing for the journey. They go forth, preach repentance, cast out demons, and anoint the sick." },
"02-05": { season: "Memorial", title: "St. Agatha", ref: "Mark 6:14-29", verse: "John, whom I beheaded, has been raised up.", summary: "Herod hears of Jesus and fears John the Baptist has risen. The account of John's martyrdom: Herod imprisons John, his daughter's dance leads to the request for John's head on a platter." },
"02-06": { season: "Memorial", title: "Sts. Paul Miki and Companions", ref: "Mark 6:30-34", verse: "Come away by yourselves to a deserted place and rest a while.", summary: "The Apostles return from their mission and Jesus invites them to rest. But the crowd follows. Jesus sees them like sheep without a shepherd and begins to teach them." },
"02-07": { season: "Ordinary Time", title: "Saturday — 4th Week of Ordinary Time", ref: "Mark 6:30-34", verse: "He had compassion for them, for they were like sheep without a shepherd.", summary: "Jesus sees the vast crowd and is moved with compassion. Despite his own need for rest, he teaches them at length. This leads into the feeding of the five thousand." },
"02-08": { season: "Ordinary Time", title: "5th Sunday of Ordinary Time — Year C", ref: "Luke 5:1-11", verse: "Do not be afraid; from now on you will be catching men.", summary: "By the Lake of Gennesaret, Jesus borrows Simon's boat to teach. He then tells Simon to put out into deep water. The miraculous catch of fish overwhelms them. Simon falls at Jesus' knees and confesses his sinfulness." },
"02-09": { season: "Ordinary Time", title: "Monday — 5th Week of Ordinary Time", ref: "Mark 6:53-56", verse: "As many as touched it were healed.", summary: "Jesus and the disciples land at Gennesaret. The people recognize him and bring the sick throughout the region. Wherever he went — villages, towns, countryside — the sick were healed by touching the tassel of his cloak." },
"02-10": { season: "Memorial", title: "St. Scholastica", ref: "Mark 7:1-13", verse: "You disregard God's commandment but cling to human tradition.", summary: "The Pharisees question Jesus about handwashing traditions. Jesus rebukes them with Isaiah's prophecy about honoring God with lips while hearts are far away. He shows how they set aside God's commandment for their tradition." },
"02-11": { season: "Memorial", title: "Our Lady of Lourdes", ref: "Mark 7:14-23", verse: "Nothing that enters one from outside can defile that person; but the things that come out from within are what defile.", summary: "Jesus calls the crowd and explains what truly makes a person unclean: evil thoughts, unchastity, theft, murder, adultery — all these come from within and defile." },
"02-12": { season: "Ordinary Time", title: "Thursday — 5th Week of Ordinary Time", ref: "Mark 7:24-30", verse: "For saying this, you may go. The demon has gone out of your daughter.", summary: "In Tyre, a Syrophoenician woman begs Jesus to drive a demon from her daughter. When Jesus responds about children's bread, she answers wisely and Jesus grants her request." },
"02-13": { season: "Ordinary Time", title: "Friday — 5th Week of Ordinary Time", ref: "Mark 7:31-37", verse: "Ephphatha! — that is, Be opened!", summary: "Jesus heals a deaf man with a speech impediment in the Decapolis region. He puts his fingers in the man's ears, touches his tongue with spittle, and says Ephphatha. The man can hear and speak plainly." },
"02-14": { season: "Memorial", title: "Sts. Cyril and Methodius", ref: "Mark 8:1-10", verse: "My heart is moved with pity for the crowd.", summary: "Jesus feeds four thousand people with seven loaves and a few fish in a deserted place. Seven baskets of fragments remain. He then dismisses the crowd and crosses to Dalmanutha by boat." },
"02-15": { season: "Ordinary Time", title: "6th Sunday of Ordinary Time — Year C", ref: "Luke 6:17, 20-26", verse: "Blessed are you who are poor, for the Kingdom of God is yours.", summary: "The Sermon on the Plain: Jesus declares the poor, the hungry, the weeping, and the persecuted blessed. He pronounces woe on the rich, the satisfied, those who laugh, and those who are praised." },
"02-16": { season: "Ordinary Time", title: "Monday — 6th Week of Ordinary Time", ref: "Mark 8:11-13", verse: "Why does this generation seek a sign?", summary: "The Pharisees demand a sign from heaven to test Jesus. He sighs deeply and refuses to give this generation a sign. He gets back in the boat and crosses to the other shore." },
"02-17": { season: "Ordinary Time", title: "Tuesday — 6th Week of Ordinary Time", ref: "Mark 8:14-21", verse: "Do you not yet understand or comprehend?", summary: "The disciples forget bread. Jesus warns about the leaven of the Pharisees and Herod. When they think he means literal bread, Jesus recalls the multiplications of loaves and asks if they still do not understand." },
"02-18": { season: "Lent", title: "Ash Wednesday", ref: "Matthew 6:1-6, 16-18", verse: "Your Father who sees what is hidden will repay you.", summary: "Jesus warns against performing deeds of mercy, prayer, and fasting for human praise. All three acts — almsgiving, prayer, fasting — should be done in secret, for the Father who sees in secret." },
"02-19": { season: "Lent", title: "Thursday after Ash Wednesday", ref: "Luke 9:22-25", verse: "What profit is there for one to gain the whole world yet lose or forfeit himself?", summary: "Jesus predicts his Passion and resurrection. He calls all to daily cross-bearing to follow him. Whoever loses his life for Jesus' sake will save it." },
"02-20": { season: "Lent", title: "Friday after Ash Wednesday", ref: "Matthew 9:14-15", verse: "The days will come when the bridegroom is taken away, and then they will fast.", summary: "John's disciples ask why they and the Pharisees fast but Jesus' disciples do not. Jesus answers: the wedding guests cannot mourn while the bridegroom is with them — but the time will come." },
"02-21": { season: "Lent", title: "Saturday after Ash Wednesday / St. Peter Damian", ref: "Luke 5:27-32", verse: "I have not come to call the righteous to repentance but sinners.", summary: "Jesus calls Levi from the tax booth. At dinner with tax collectors, the Pharisees question his disciples. Jesus answers that the healthy need no physician — he came for sinners." },
"02-22": { season: "Lent", title: "1st Sunday of Lent — Year C", ref: "Luke 4:1-13", verse: "One does not live on bread alone.", summary: "Filled with the Holy Spirit, Jesus is led through the desert for 40 days. He is tempted three times by the devil: to turn stone to bread, to worship the devil for worldly power, to throw himself from the Temple. He resists each with Scripture." },
"02-23": { season: "Lent", title: "Monday — 1st Week of Lent / St. Polycarp", ref: "Matthew 25:31-46", verse: "Whatever you did for one of the least brothers of mine, you did for me.", summary: "The Final Judgment: the Son of Man separates the sheep from the goats. The righteous fed the hungry, welcomed the stranger, clothed the naked, cared for the sick, visited prisoners — and in doing so, served Christ himself." },
"02-24": { season: "Lent", title: "Tuesday — 1st Week of Lent", ref: "Matthew 6:7-15", verse: "This is how you are to pray: Our Father...", summary: "Jesus teaches his disciples not to babble in prayer like the pagans. He gives them the Our Father — the Lord's Prayer — as the model of Christian prayer." },
"02-25": { season: "Lent", title: "Wednesday — 1st Week of Lent", ref: "Luke 11:29-32", verse: "No sign will be given except the sign of Jonah.", summary: "Jesus refuses a sign to the evil generation. Jonah was a sign to the Ninevites; the Son of Man will be a sign to this generation. The Queen of the South and the Ninevites will rise up to condemn this generation." },
"02-26": { season: "Lent", title: "Thursday — 1st Week of Lent", ref: "Matthew 7:7-12", verse: "Ask and it will be given to you; seek and you will find.", summary: "Jesus teaches persistence in prayer: ask, seek, knock. A father gives good things to his children; how much more will the heavenly Father give good things to those who ask. The Golden Rule: do to others as you would have them do to you." },
"02-27": { season: "Lent", title: "Friday — 1st Week of Lent", ref: "Matthew 5:20-26", verse: "Unless your righteousness surpasses that of the scribes and Pharisees, you will not enter the Kingdom of heaven.", summary: "Jesus deepens the commandment against killing: anger and contempt are already sinful. Be reconciled with your brother before bringing your gift to the altar. Settle with your opponent quickly." },
"02-28": { season: "Lent", title: "Saturday — 1st Week of Lent", ref: "Matthew 5:43-48", verse: "Be perfect, just as your heavenly Father is perfect.", summary: "Jesus commands love of enemies and prayer for persecutors. God makes his sun rise on the bad and the good alike. Even pagans love those who love them — we must be perfect as the heavenly Father is perfect." },

// ==================== MARCH ====================
"03-01": { season: "Lent", title: "2nd Sunday of Lent — Year C", ref: "Luke 9:28-36", verse: "This is my chosen Son; listen to him.", summary: "The Transfiguration on the mountain: Jesus' face changes and his clothing becomes dazzling white. Moses and Elijah appear and speak of his 'exodus' in Jerusalem. The Father's voice from the cloud commands the disciples to listen to Jesus." },
"03-02": { season: "Lent", title: "Monday — 2nd Week of Lent", ref: "Luke 6:36-38", verse: "Be merciful, just as your Father is merciful.", summary: "Jesus teaches: stop judging, stop condemning, forgive and you will be forgiven. Give and gifts will be given to you — a good measure, packed, shaken, and overflowing, will be poured into your lap." },
"03-03": { season: "Lent", title: "Tuesday — 2nd Week of Lent", ref: "Matthew 23:1-12", verse: "The greatest among you must be your servant.", summary: "Jesus warns against the example of the scribes and Pharisees who preach but do not practice. Do not seek titles of honor. Whoever exalts himself will be humbled; whoever humbles himself will be exalted." },
"03-04": { season: "Lent", title: "Wednesday — 2nd Week of Lent / St. Casimir", ref: "Matthew 20:17-28", verse: "Whoever wishes to be great among you shall be your servant.", summary: "Jesus predicts his Passion a third time. The mother of James and John asks for places of honor. Jesus teaches servant leadership: the Son of Man came not to be served but to serve and give his life as a ransom for many." },
"03-05": { season: "Lent", title: "Thursday — 2nd Week of Lent", ref: "Luke 16:19-31", verse: "Between us and you a great chasm is established.", summary: "The Rich Man and Lazarus: the beggar at the rich man's gate dies and is carried to Abraham's bosom. The rich man dies and suffers in the netherworld. Even if someone rose from the dead, those who reject Moses and the prophets would not listen." },
"03-06": { season: "Lent", title: "Friday — 2nd Week of Lent", ref: "Matthew 21:33-43, 45-46", verse: "The stone that the builders rejected has become the cornerstone.", summary: "The Parable of the Tenants: the landowner sends servants and finally his son, who is killed. Jesus quotes the rejected stone psalm and announces the kingdom will be given to a people producing its fruits." },
"03-07": { season: "Lent", title: "Saturday — 2nd Week / Sts. Perpetua and Felicity", ref: "Luke 15:1-3, 11-32", verse: "This son of mine was dead, and has come to life again.", summary: "The Parable of the Prodigal Son: a son squanders his inheritance, returns home in repentance, and is welcomed with a feast by his rejoicing father. The elder son's resentment is gently challenged. The father represents God's lavish mercy." },
"03-08": { season: "Lent", title: "3rd Sunday of Lent — Year C / St. John of God", ref: "Luke 13:1-9", verse: "Unless you repent, you will all perish as they did!", summary: "Jesus addresses two tragedies, saying the victims were not greater sinners. He calls all to repentance. The Parable of the Fig Tree: give it one more year of care before cutting it down." },
"03-09": { season: "Lent", title: "Monday — 3rd Week of Lent / St. Frances of Rome", ref: "Luke 4:24-30", verse: "No prophet is accepted in his own native place.", summary: "Jesus in Nazareth recalls how Elijah was sent to a widow of Sidon and Elisha cleansed a Syrian leper — Gentiles received what Israel rejected. The crowd is furious and tries to throw him off a cliff, but he passes through their midst." },
"03-10": { season: "Lent", title: "Tuesday — 3rd Week of Lent", ref: "Matthew 18:21-35", verse: "I say to you, not seven times but seventy-seven times.", summary: "Peter asks how many times to forgive. Jesus answers: seventy-seven times. The Parable of the Unforgiving Servant: forgiven an enormous debt, the servant refuses to forgive a small one. The master hands him over to the torturers." },
"03-11": { season: "Lent", title: "Wednesday — 3rd Week of Lent", ref: "Matthew 5:17-19", verse: "I have come not to abolish but to fulfill.", summary: "Jesus declares he has come not to abolish the Law and the prophets but to fulfill them. Not a single letter will pass from the law until all is accomplished. Those who keep and teach the commandments will be great in the Kingdom." },
"03-12": { season: "Lent", title: "Thursday — 3rd Week of Lent", ref: "Luke 11:14-23", verse: "Whoever is not with me is against me.", summary: "Jesus drives out a mute demon. Accused of acting through Beelzebul, he refutes this logically: a kingdom divided against itself is ruined. If by the finger of God he casts out demons, the Kingdom of God has come upon them." },
"03-13": { season: "Lent", title: "Friday — 3rd Week of Lent", ref: "Mark 12:28-34", verse: "You shall love the Lord your God with all your heart.", summary: "A scribe asks which commandment is first. Jesus gives the two great commandments: love God with all your heart, soul, mind, and strength; and love your neighbor as yourself. The scribe agrees, and Jesus says he is not far from the Kingdom." },
"03-14": { season: "Lent", title: "Saturday — 3rd Week of Lent", ref: "Luke 18:9-14", verse: "Everyone who exalts himself will be humbled, and the one who humbles himself will be exalted.", summary: "The Parable of the Pharisee and the Tax Collector. The Pharisee thanks God for his virtues; the tax collector beats his breast: 'God, be merciful to me a sinner.' Only the tax collector goes home justified." },
"03-15": { season: "Lent", title: "4th Sunday of Lent (Laetare) — Year C", ref: "Luke 15:1-3, 11-32", verse: "Let us celebrate with a feast, because this son of mine was dead, and has come to life again.", summary: "The Parable of the Prodigal Son. The father runs to meet his returning son, calls for a celebration, and explains to the resentful elder son: your brother was dead and has come back to life. A powerful image of God's mercy." },
"03-16": { season: "Lent", title: "Monday — 4th Week of Lent", ref: "John 4:43-54", verse: "Sir, come down before my child dies.", summary: "A royal official from Capernaum begs Jesus to heal his dying son. Jesus says his son will live. The official believes and departs. He learns the boy recovered at the very hour Jesus spoke. His whole household believes." },
"03-17": { season: "Lent", title: "Tuesday — 4th Week / St. Patrick", ref: "John 5:1-16", verse: "Rise, take up your mat, and walk.", summary: "At the pool of Bethesda, Jesus heals a man who has been ill for thirty-eight years. Told to carry his mat on the Sabbath, he is reported to the Jews. Jesus finds him in the Temple and tells him to sin no more." },
"03-18": { season: "Lent", title: "Wednesday — 4th Week / St. Cyril of Jerusalem", ref: "John 5:17-30", verse: "The Son cannot do anything on his own, but only what he sees the Father doing.", summary: "Jesus teaches his unity of action with the Father. The Father has given him authority to judge and to give life. Whoever hears his word and believes has eternal life and will not come to judgment." },
"03-19": { season: "Solemnity", title: "St. Joseph, Spouse of the Blessed Virgin Mary", ref: "Matthew 1:16, 18-21, 24", verse: "Joseph, son of David, do not be afraid to take Mary your wife into your home.", summary: "When Joseph learns Mary is with child, he plans to divorce her quietly. An angel appears in a dream and reveals the child is of the Holy Spirit. Joseph wakes and does as the angel commanded, taking Mary as his wife." },
"03-20": { season: "Lent", title: "Friday — 4th Week of Lent", ref: "John 7:1-2, 10, 25-30", verse: "They tried to arrest him, but no one laid a hand upon him, because his hour had not yet come.", summary: "Jesus goes to Jerusalem for the feast, teaching in the Temple. People debate whether he could be the Messiah. Some try to arrest him, but no one can because his hour has not yet come." },
"03-21": { season: "Lent", title: "Saturday — 4th Week of Lent", ref: "John 7:40-53", verse: "Never before has anyone spoken like this man.", summary: "The crowd debates whether Jesus is the Prophet or the Messiah. Guards sent to arrest him return empty-handed, saying no one has ever spoken like him. Nicodemus defends giving Jesus a hearing, but is dismissed." },
"03-22": { season: "Lent", title: "5th Sunday of Lent — Year C", ref: "John 8:1-11", verse: "Neither do I condemn you. Go, and from now on do not sin any more.", summary: "The woman caught in adultery is brought before Jesus. He invites the sinless one to cast the first stone. One by one they leave. Jesus tells the woman he does not condemn her and calls her to sin no more." },
"03-23": { season: "Lent", title: "Monday — 5th Week of Lent / St. Turibius of Mogrovejo", ref: "John 8:12-20", verse: "I am the light of the world.", summary: "Jesus declares himself the light of the world. The Pharisees challenge his testimony. He responds that his Father also bears witness — his Father who sent him. They did not understand that he spoke of the Father." },
"03-24": { season: "Lent", title: "Tuesday — 5th Week of Lent", ref: "John 8:21-30", verse: "When you lift up the Son of Man, then you will realize that I AM.", summary: "Jesus tells the Jews he is going where they cannot come. He declares: You are from below, I am from above. When you lift up the Son of Man, you will know I AM. As he speaks, many come to believe in him." },
"03-25": { season: "Solemnity", title: "Annunciation of the Lord", ref: "Luke 1:26-38", verse: "Behold, I am the handmaid of the Lord. May it be done to me according to your word.", summary: "Gabriel is sent to Mary in Nazareth. He greets her as full of grace, announces she will conceive the Son of God through the Holy Spirit. Mary's yes — her fiat — is the hinge of salvation history." },
"03-26": { season: "Lent", title: "Thursday — 5th Week of Lent", ref: "John 8:51-59", verse: "Before Abraham came to be, I AM.", summary: "Jesus says whoever keeps his word will never see death. The Jews are outraged. Jesus declares: Abraham rejoiced to see my day. Before Abraham was, I AM. They pick up stones but he hides and leaves the Temple." },
"03-27": { season: "Lent", title: "Friday — 5th Week of Lent", ref: "John 10:31-42", verse: "The works I do in my Father's name testify to me.", summary: "The Jews take up stones to stone Jesus for blasphemy. He appeals to his works as testimony. He withdraws beyond the Jordan where John used to baptize, and many believe there." },
"03-28": { season: "Lent", title: "Saturday — 5th Week of Lent", ref: "John 11:45-56", verse: "It is better for you that one man die instead of the people.", summary: "After the raising of Lazarus, the chief priests and Pharisees call a council. Caiaphas prophesies that it is better for one man to die for the nation. From that day they plan to kill Jesus." },
"03-29": { season: "Holy Week", title: "Palm Sunday — Year C", ref: "Luke 22:14 — 23:56", verse: "Father, into your hands I commend my spirit.", summary: "The Passion of the Lord according to Luke. The Last Supper, agony in Gethsemane, arrest, trials before Pilate and Herod, crucifixion, death. Jesus forgives those who crucify him, promises paradise to the repentant thief, and dies commending his spirit to the Father." },
"03-30": { season: "Holy Week", title: "Monday of Holy Week", ref: "John 12:1-11", verse: "Leave her alone. Let her keep this for the day of my burial.", summary: "Mary of Bethany anoints Jesus' feet with costly perfumed oil and wipes them with her hair. Judas objects. Jesus defends her: she has kept it for his burial. The poor you always have with you." },
"03-31": { season: "Holy Week", title: "Tuesday of Holy Week", ref: "John 13:21-33, 36-38", verse: "What you are going to do, do quickly.", summary: "At the Last Supper, Jesus is troubled and announces that one of those present will betray him. He indicates Judas by the morsel of bread. After Judas leaves, Peter says he will lay down his life. Jesus predicts Peter will deny him three times." },

// ==================== APRIL ====================
"04-01": { season: "Holy Week", title: "Wednesday of Holy Week (Spy Wednesday)", ref: "Matthew 26:14-25", verse: "Surely it is not I, Lord?", summary: "Judas goes to the chief priests and agrees to hand Jesus over for thirty pieces of silver. At the Passover meal, Jesus reveals that one of the Twelve will betray him. Each asks: 'Surely it is not I, Lord?'" },
"04-02": { season: "Holy Week", title: "Holy Thursday — Mass of the Lord's Supper", ref: "John 13:1-15", verse: "If I, therefore, the master and teacher, have washed your feet, you ought to wash one another's feet.", summary: "Before the feast of Passover, Jesus rises from table, removes his outer garments, and washes the feet of his disciples. Peter protests. Jesus teaches that the master who serves is the model for all." },
"04-03": { season: "Holy Week", title: "Good Friday — Passion of the Lord", ref: "John 18:1 — 19:42", verse: "It is finished.", summary: "The Passion according to John: the arrest in Gethsemane, Jesus before Annas and Caiaphas, Peter's denial, trial before Pilate, the carrying of the cross, crucifixion, death, side pierced with a lance, burial by Joseph of Arimathea and Nicodemus." },
"04-04": { season: "Easter Triduum", title: "Holy Saturday — Easter Vigil", ref: "Luke 24:1-12", verse: "Why do you seek the living one among the dead? He is not here, but he has been raised.", summary: "At dawn, the women find the stone rolled away and the tomb empty. Two men in dazzling garments ask why they seek the living among the dead. The women report to the Eleven, who do not believe. Peter runs to the tomb and finds only the burial cloths." },
"04-05": { season: "Easter", title: "Easter Sunday — Resurrection of the Lord", ref: "John 20:1-9", verse: "He saw and believed.", summary: "Mary Magdalene runs to tell Simon Peter and the beloved disciple that the tomb is empty. Peter and the beloved disciple run to the tomb. The beloved disciple sees the burial cloths and believes. They did not yet understand the Scripture." },
"04-06": { season: "Easter", title: "Monday within the Octave of Easter", ref: "Matthew 28:8-15", verse: "Do not be afraid. Go tell my brothers to go to Galilee.", summary: "The women leave the tomb with fear and great joy. Jesus meets them, and they embrace his feet. He sends them to tell his brothers to go to Galilee. The guards are bribed to spread the false story of theft." },
"04-07": { season: "Easter", title: "Tuesday within the Octave of Easter", ref: "John 20:11-18", verse: "I have seen the Lord!", summary: "Mary Magdalene remains weeping at the tomb. She meets the Risen Jesus, thinking he is the gardener. When he calls her by name — 'Mary!' — she recognizes him. He sends her to tell the disciples he is ascending to his Father." },
"04-08": { season: "Easter", title: "Wednesday within the Octave of Easter", ref: "Luke 24:13-35", verse: "Were not our hearts burning while he spoke to us on the way?", summary: "The Road to Emmaus: two disciples walk with the Risen Jesus without recognizing him. He opens the Scriptures to them. At table, he breaks bread and vanishes. They return to Jerusalem saying their hearts burned within them." },
"04-09": { season: "Easter", title: "Thursday within the Octave of Easter", ref: "Luke 24:35-48", verse: "Peace be with you.", summary: "Jesus appears among the disciples, shows his hands and feet, eats broiled fish to prove he is not a ghost. He opens their minds to understand the Scriptures and commissions them to preach repentance to all nations." },
"04-10": { season: "Easter", title: "Friday within the Octave of Easter", ref: "John 21:1-14", verse: "Cast the net over the right side of the boat and you will find something.", summary: "The miraculous catch of fish after the Resurrection. The beloved disciple recognizes Jesus. Peter jumps into the sea. Jesus has a charcoal fire with bread and fish. He gives them to eat. This was the third time Jesus appeared." },
"04-11": { season: "Easter", title: "Saturday within the Octave / St. Stanislaus", ref: "Mark 16:9-15", verse: "Go into the whole world and proclaim the Gospel to every creature.", summary: "The Risen Jesus appears first to Mary Magdalene, then to two disciples, then to the Eleven at table. He rebukes their unbelief and sends them to proclaim the Gospel to all creation." },
"04-12": { season: "Easter", title: "Divine Mercy Sunday (2nd Sunday of Easter) — Year C", ref: "John 20:19-31", verse: "Blessed are those who have not seen and have believed.", summary: "Jesus appears to the disciples and breathes the Holy Spirit on them, giving them authority to forgive sins. A week later he appears to Thomas, inviting him to touch his wounds. Thomas confesses: 'My Lord and my God!'" },
"04-13": { season: "Easter", title: "Monday — 2nd Week of Easter", ref: "John 3:1-8", verse: "No one can see the Kingdom of God without being born from above.", summary: "Nicodemus comes to Jesus by night. Jesus tells him he must be born again of water and Spirit to enter the Kingdom. What is born of flesh is flesh; what is born of Spirit is spirit." },
"04-14": { season: "Easter", title: "Tuesday — 2nd Week of Easter", ref: "John 3:7-15", verse: "So must the Son of Man be lifted up.", summary: "Jesus continues with Nicodemus about heavenly things. Just as Moses lifted up the serpent in the desert, so must the Son of Man be lifted up — so that everyone who believes may have eternal life." },
"04-15": { season: "Easter", title: "Wednesday — 2nd Week of Easter", ref: "John 3:16-21", verse: "For God so loved the world that he gave his only Son.", summary: "The heart of the Gospel: God loved the world so much that he gave his only Son so that all who believe may have eternal life. Light has come into the world, but people preferred darkness." },
"04-16": { season: "Easter", title: "Thursday — 2nd Week of Easter", ref: "John 3:31-36", verse: "Whoever believes in the Son has eternal life.", summary: "The one who comes from above is above all. He testifies to what he has seen, but his testimony is not accepted. Whoever accepts his testimony certifies that God is trustworthy." },
"04-17": { season: "Easter", title: "Friday — 2nd Week of Easter", ref: "John 6:1-15", verse: "Where can we buy enough food for them to eat?", summary: "The feeding of the five thousand. A boy has five barley loaves and two fish. Jesus gives thanks, distributes, and all are satisfied. Twelve baskets of fragments remain. The people want to make him king." },
"04-18": { season: "Easter", title: "Saturday — 2nd Week of Easter", ref: "John 6:16-21", verse: "It is I. Do not be afraid!", summary: "The disciples cross the sea without Jesus. A strong wind rises. Suddenly Jesus comes walking on the sea and says: It is I. Do not be afraid. They want to take him into the boat; immediately it reaches shore." },
"04-19": { season: "Easter", title: "3rd Sunday of Easter — Year C", ref: "John 21:1-19", verse: "Simon, son of John, do you love me?", summary: "The miraculous catch. After breakfast, Jesus asks Peter three times: Do you love me? Three times Peter answers yes. Three times Jesus entrusts him: Feed my lambs. Tend my sheep. Peter's threefold declaration of love repairs his threefold denial." },
"04-20": { season: "Easter", title: "Monday — 3rd Week of Easter", ref: "John 6:22-29", verse: "Do not work for food that perishes but for the food that endures for eternal life.", summary: "The crowd follows Jesus across the sea seeking more bread. He tells them not to work for perishable food but for eternal life. The work of God is to believe in the one he sent." },
"04-21": { season: "Easter", title: "Tuesday — 3rd Week of Easter / St. Anselm", ref: "John 6:30-35", verse: "I am the bread of life; whoever comes to me will never hunger.", summary: "The crowd asks for a sign. Jesus says Moses gave the bread from heaven; the Father gives the true bread from heaven. I am the bread of life: whoever comes to me will never hunger or thirst." },
"04-22": { season: "Easter", title: "Wednesday — 3rd Week of Easter", ref: "John 6:35-40", verse: "Everyone who sees the Son and believes in him may have eternal life.", summary: "Jesus declares: Everyone the Father gives me will come to me; I will not reject anyone who comes. This is the will of my Father — that everyone who believes in the Son should have eternal life and be raised on the last day." },
"04-23": { season: "Easter", title: "Thursday — 3rd Week of Easter / St. George", ref: "John 6:44-51", verse: "I am the living bread that came down from heaven.", summary: "No one can come to Jesus unless drawn by the Father. Jesus is the bread of life. The ancestors ate manna and died; this bread from heaven gives eternal life. The bread is his flesh, given for the life of the world." },
"04-24": { season: "Easter", title: "Friday — 3rd Week of Easter / St. Fidelis of Sigmaringen", ref: "John 6:52-59", verse: "My flesh is true food, and my blood is true drink.", summary: "The Jews dispute among themselves: How can he give us his flesh? Jesus insists: unless you eat the flesh of the Son of Man and drink his blood, you have no life. His flesh is true food, his blood true drink. Whoever eats this bread will live forever." },
"04-25": { season: "Feast", title: "St. Mark the Evangelist", ref: "Mark 16:15-20", verse: "Go into the whole world and proclaim the Gospel.", summary: "The Risen Christ commissions the Eleven: proclaim the Gospel to all creation, baptize, and these signs will accompany believers. The Lord worked with them and confirmed the word through the signs that followed." },
"04-26": { season: "Easter", title: "4th Sunday of Easter (Good Shepherd Sunday) — Year C", ref: "John 10:27-30", verse: "My sheep hear my voice; I know them, and they follow me.", summary: "Jesus the Good Shepherd: my sheep hear my voice, I know them, and they follow me. I give them eternal life; they shall never perish. No one can take them from my hand. The Father and I are one." },
"04-27": { season: "Easter", title: "Monday — 4th Week of Easter", ref: "John 10:1-10", verse: "I am the gate for the sheep.", summary: "The parable of the sheepfold. The shepherd enters through the gate; the thief climbs over the wall. The sheep hear the shepherd's voice and follow him. Jesus declares: I am the gate — whoever enters through me will be saved." },
"04-28": { season: "Easter", title: "Tuesday — 4th Week of Easter / St. Louis de Montfort", ref: "John 10:22-30", verse: "My Father, who has given them to me, is greater than all.", summary: "At the feast of Dedication, the Jews ask Jesus plainly if he is the Messiah. He says his works speak for him, but they do not believe because they are not among his sheep. He and the Father are one." },
"04-29": { season: "Memorial", title: "St. Catherine of Siena — Feast", ref: "John 15:1-8", verse: "I am the vine, you are the branches.", summary: "Jesus declares: I am the true vine and my Father is the vine grower. Every branch that bears no fruit is cut away; every fruitful branch is pruned. Remain in me as I remain in you. Apart from me you can do nothing." },
"04-30": { season: "Easter", title: "Thursday — 4th Week of Easter / St. Pius V", ref: "John 13:16-20", verse: "Whoever receives the one I send receives me.", summary: "No slave is greater than his master. Knowing this, the disciples will be blessed if they act on it. The one who receives whom Jesus sends, receives Jesus himself, and the Father who sent him." },

// ==================== MAY ====================
"05-01": { season: "Easter", title: "St. Joseph the Worker / Friday 4th Week of Easter", ref: "John 14:1-6", verse: "I am the way and the truth and the life.", summary: "Do not let your hearts be troubled. In my Father's house there are many dwelling places. Thomas asks how they can know the way. Jesus declares: I am the way, the truth, and the life. No one comes to the Father except through me." },
"05-02": { season: "Memorial", title: "St. Athanasius", ref: "John 14:7-14", verse: "Whoever has seen me has seen the Father.", summary: "Philip asks Jesus to show them the Father. Jesus responds: have I been with you so long without your knowing me? Whoever has seen me has seen the Father. Whatever you ask in my name, I will do it." },
"05-03": { season: "Feast", title: "Sts. Philip and James, Apostles", ref: "John 14:6-14", verse: "I am the way and the truth and the life.", summary: "Philip asks Jesus to show them the Father. Jesus reveals that he is in the Father and the Father is in him. The Father who dwells in Jesus does his works. Believe in Jesus' works and ask anything in his name." },
"05-04": { season: "Easter", title: "Monday — 5th Week of Easter", ref: "John 14:21-26", verse: "The Holy Spirit will teach you everything and remind you of all that I told you.", summary: "Whoever loves Jesus keeps his commandments and will be loved by the Father. Jesus and the Father will come and make their dwelling with that person. The Advocate, the Holy Spirit, will teach and remind them of everything." },
"05-05": { season: "Easter", title: "Tuesday — 5th Week of Easter", ref: "John 14:27-31", verse: "Peace I leave with you; my peace I give to you.", summary: "Jesus' farewell gift is his peace — not as the world gives. Do not be troubled or afraid. He is going away but will return. The prince of this world has no power over him, and his obedience to the Father must be shown to the world." },
"05-06": { season: "Easter", title: "Wednesday — 5th Week of Easter", ref: "John 15:1-8", verse: "Remain in me, as I remain in you.", summary: "Jesus the true vine: the Father prunes fruitful branches so they bear more fruit. Remaining in Jesus produces much fruit; apart from him nothing is possible. Those who remain in him and he in them may ask for anything." },
"05-07": { season: "Easter", title: "Thursday — 5th Week of Easter", ref: "John 15:9-11", verse: "Remain in my love.", summary: "As the Father has loved Jesus, so he loves his disciples. Remain in his love by keeping his commandments, just as he keeps his Father's commandments. Jesus speaks so that his joy may be in them and their joy may be complete." },
"05-08": { season: "Easter", title: "Friday — 5th Week of Easter", ref: "John 15:12-17", verse: "Love one another as I love you.", summary: "The commandment of love: love one another as Jesus has loved us. The greatest love is to lay down one's life for one's friends. Jesus calls them friends, not slaves. He chose them to go and bear fruit that will remain." },
"05-09": { season: "Easter", title: "Saturday — 5th Week of Easter", ref: "John 15:18-21", verse: "If the world hates you, realize that it hated me first.", summary: "Jesus prepares the disciples: the world hated him before them. They do not belong to the world, so the world hates them. They will be persecuted for his name's sake, for the world does not know the Father." },
"05-10": { season: "Easter", title: "6th Sunday of Easter — Year C", ref: "John 14:23-29", verse: "The Holy Spirit will teach you everything.", summary: "Whoever loves Jesus will keep his word; the Father will love him and they will come and make their dwelling with him. The Advocate, the Holy Spirit, will teach everything and remind of all Jesus said. Peace he leaves — not as the world gives." },
"05-11": { season: "Easter", title: "Monday — 6th Week of Easter", ref: "John 15:26 — 16:4", verse: "The Advocate will testify to me.", summary: "Jesus promises the Advocate — the Spirit of truth who proceeds from the Father — will testify on his behalf. The disciples too will testify. He warns of persecution to come so they will not stumble when it happens." },
"05-12": { season: "Easter", title: "Tuesday — 6th Week of Easter / Sts. Nereus & Achilleus", ref: "John 16:5-11", verse: "It is better for you that I go.", summary: "Unless Jesus goes away, the Advocate will not come. When he comes, he will convict the world concerning sin, righteousness, and condemnation. The world's sin is not believing in Jesus." },
"05-13": { season: "Memorial", title: "Our Lady of Fatima / Wednesday 6th Week of Easter", ref: "John 16:12-15", verse: "When he comes, the Spirit of truth, he will guide you to all truth.", summary: "Jesus has much more to say but the disciples cannot bear it now. The Spirit of truth will guide them to all truth, not speaking on his own but from what he hears. He will glorify Jesus by taking what belongs to Jesus and declaring it." },
"05-14": { season: "Feast", title: "St. Matthias, Apostle", ref: "John 15:9-17", verse: "It was not you who chose me, but I who chose you.", summary: "Jesus commands love: love one another as he loves us. There is no greater love than to lay down one's life. He calls them friends. He chose them and appointed them to go and bear fruit that will remain." },
"05-15": { season: "Easter", title: "Friday — 6th Week of Easter / St. Isidore the Farmer", ref: "John 16:20-23", verse: "Your grief will become joy.", summary: "Jesus speaks of anguish turned to joy, like a woman in labor. When he rises, their hearts will rejoice with a joy no one can take. On that day they will not question him about anything but ask the Father in his name." },
"05-16": { season: "Easter", title: "Saturday — 6th Week of Easter", ref: "John 16:23-28", verse: "Ask and you will receive, so that your joy may be complete.", summary: "Until now they have not asked for anything in his name. Ask and receive so that joy may be complete. Jesus came from the Father and will return to the Father — he has conquered the world." },
"05-17": { season: "Solemnity", title: "Ascension of the Lord — Year C", ref: "Luke 24:46-53", verse: "You are witnesses of these things.", summary: "The Risen Christ opens the disciples' minds to understand Scripture. He commissions them as witnesses to all nations, promises the Holy Spirit, and is carried up into heaven. They return to Jerusalem with great joy, blessing God continually." },
"05-18": { season: "Easter", title: "Monday — 7th Week of Easter / St. John I", ref: "John 16:29-33", verse: "In the world you will have trouble, but take courage — I have conquered the world!", summary: "The disciples believe Jesus came from God. He says they will be scattered and leave him alone — though he is not alone because the Father is with him. He has spoken so they may have peace. Take courage: he has conquered the world." },
"05-19": { season: "Easter", title: "Tuesday — 7th Week of Easter", ref: "John 17:1-11", verse: "I have given glory to you on earth by accomplishing the work you gave me to do.", summary: "The Priestly Prayer of Jesus: he prays for his disciples. He completed the work the Father gave him. Eternal life is knowing the one true God and Jesus whom he sent. He asks the Father to protect his disciples." },
"05-20": { season: "Easter", title: "Wednesday — 7th Week / St. Bernardine of Siena", ref: "John 17:11-19", verse: "Consecrate them in the truth. Your word is truth.", summary: "Jesus prays that the Father keep the disciples in his name so they may be one as he and the Father are one. They are not of the world. He consecrates himself for their sake so they may be consecrated in truth." },
"05-21": { season: "Easter", title: "Thursday — 7th Week of Easter", ref: "John 17:20-26", verse: "That they may all be one, as you, Father, are in me and I in you.", summary: "Jesus prays for all future believers: that they may be one, as the Father and Son are one, so the world may believe. He wants them where he is to see his glory — the glory given him before the foundation of the world." },
"05-22": { season: "Easter", title: "Friday — 7th Week of Easter / St. Rita of Cascia", ref: "John 21:15-19", verse: "Feed my sheep.", summary: "Jesus asks Peter three times: do you love me? Three times Peter says yes. Three times Jesus says: feed my lambs, tend my sheep, feed my sheep. He then speaks of the cross Peter will carry and calls him: Follow me." },
"05-23": { season: "Easter", title: "Saturday — 7th Week of Easter / Vigil of Pentecost", ref: "John 7:37-39", verse: "Let anyone who thirsts come to me and drink.", summary: "On the last day of the feast, Jesus cries out: let the thirsty come to me and drink. Rivers of living water will flow from within those who believe. This he said about the Spirit, whom those who believed would receive." },
"05-24": { season: "Solemnity", title: "Pentecost Sunday — Year C", ref: "John 20:19-23", verse: "Receive the Holy Spirit.", summary: "The Risen Jesus appears to the disciples on Easter evening. He shows his hands and side. He breathes on them and says: Receive the Holy Spirit. Whose sins you forgive are forgiven; whose sins you retain are retained." },
"05-25": { season: "Ordinary Time", title: "Monday after Pentecost / St. Bede the Venerable", ref: "Matthew 5:1-12", verse: "Blessed are the poor in spirit, for theirs is the Kingdom of heaven.", summary: "The Beatitudes: the eight blessings Jesus pronounces on those who are poor in spirit, who mourn, the meek, those who hunger for righteousness, the merciful, the pure of heart, the peacemakers, the persecuted." },
"05-26": { season: "Memorial", title: "St. Philip Neri / Tuesday after Pentecost", ref: "Matthew 5:13-16", verse: "Your light must shine before others.", summary: "You are the salt of the earth. You are the light of the world — a city on a hill. Let your light shine before others so they may see your good works and glorify your Father." },
"05-27": { season: "Solemnity", title: "Most Holy Trinity — Year C", ref: "John 16:12-15", verse: "Everything that the Father has is mine.", summary: "The Spirit of truth will guide the disciples to all truth. He will not speak on his own but will speak what he hears and declare what is to come. He will glorify Jesus by taking from what belongs to Jesus and declaring it." },
"05-28": { season: "Ordinary Time", title: "Thursday — 8th Week of Ordinary Time", ref: "Mark 10:46-52", verse: "Master, I want to see.", summary: "Blind Bartimaeus cries out: Jesus, son of David, have pity on me! Jesus calls him: your faith has saved you. Immediately Bartimaeus receives sight and follows Jesus on the way." },
"05-29": { season: "Ordinary Time", title: "Friday — 8th Week of Ordinary Time", ref: "Mark 11:11-26", verse: "Have faith in God!", summary: "Jesus curses the fig tree. He cleanses the Temple. The next day the withered fig tree amazes the disciples. Jesus teaches: have faith in God; if you believe, whatever you ask for in prayer will be granted." },
"05-30": { season: "Ordinary Time", title: "Saturday — 8th Week of Ordinary Time", ref: "Mark 11:27-33", verse: "By what authority are you doing these things?", summary: "The chief priests, scribes, and elders question Jesus' authority. He responds with a question about John's baptism — was it from heaven or of human origin? They refuse to answer, so he refuses to answer them." },
"05-31": { season: "Feast", title: "Visitation of the Blessed Virgin Mary", ref: "Luke 1:39-56", verse: "And why is this granted to me, that the mother of my Lord should come to me?", summary: "Mary visits Elizabeth. At Mary's greeting, the infant John leaps in the womb. Elizabeth cries out her blessing. Mary responds with the Magnificat: My soul proclaims the greatness of the Lord." },

// ==================== JUNE ====================
"06-01": { season: "Solemnity", title: "Body and Blood of Christ (Corpus Christi) — Year C / St. Justin", ref: "Luke 9:11-17", verse: "They all ate and were satisfied.", summary: "Jesus welcomes the crowds, speaks of the Kingdom, and heals. At evening the disciples want to send the people away, but Jesus says: give them some food. Five loaves and two fish feed five thousand. Twelve baskets remain — pointing to the Eucharist." },
"06-02": { season: "Ordinary Time", title: "Tuesday — 9th Week of Ordinary Time", ref: "Mark 12:13-17", verse: "Repay to Caesar what belongs to Caesar and to God what belongs to God.", summary: "The Pharisees and Herodians try to trap Jesus with the question of taxes. He asks whose image is on the coin — Caesar's. Repay Caesar what is Caesar's, and God what is God's. They are utterly amazed." },
"06-03": { season: "Memorial", title: "Sts. Charles Lwanga and Companions, Martyrs", ref: "Mark 12:18-27", verse: "God is not the God of the dead but of the living.", summary: "The Sadducees test Jesus about the resurrection. He refutes them: in the resurrection they neither marry nor are given in marriage. God is not the God of the dead but the living. They are greatly misled." },
"06-04": { season: "Ordinary Time", title: "Thursday — 9th Week of Ordinary Time", ref: "Mark 12:28-34", verse: "You are not far from the Kingdom of God.", summary: "A scribe asks which commandment is first. Jesus gives the twofold commandment of love. The scribe agrees wholeheartedly. Jesus says to him: you are not far from the Kingdom. After this no one dared to question him." },
"06-05": { season: "Memorial", title: "St. Boniface, Bishop and Martyr", ref: "Mark 12:35-37", verse: "David himself calls him Lord; so how is he his son?", summary: "Jesus teaches in the Temple: if David calls the Messiah 'Lord,' how can the Messiah be David's son? The implication is that the Messiah is more than a human descendant — he is divine. The crowd listens with delight." },
"06-06": { season: "Ordinary Time", title: "Saturday — 9th Week of Ordinary Time / St. Norbert", ref: "Mark 12:38-44", verse: "She gave from her poverty, all she had.", summary: "Jesus condemns the scribes who devour widows' houses while making lengthy prayers. He observes the treasury: a poor widow puts in two small coins. She gave from her poverty — more than all the wealthy who gave from surplus." },
"06-07": { season: "Solemnity", title: "Most Sacred Heart of Jesus — Year C", ref: "Luke 15:3-7", verse: "There will be more joy in heaven over one sinner who repents than over ninety-nine righteous people who have no need of repentance.", summary: "The Parable of the Lost Sheep: the shepherd leaves ninety-nine to search for the one that is lost. When found, he celebrates. This images the Sacred Heart of Jesus — the heart that seeks the lost, celebrates the found, and burns with love for every soul." },
"06-08": { season: "Ordinary Time", title: "Immaculate Heart of Mary / Monday 10th Week", ref: "Matthew 5:1-12", verse: "Blessed are the pure in heart, for they will see God.", summary: "The Beatitudes of the Sermon on the Mount. The Immaculate Heart of Mary is the perfect model of the beatitude of purity of heart. Mary's heart, undivided in its love for God, is the heart that sees God face to face." },
"06-09": { season: "Ordinary Time", title: "Tuesday — 10th Week of Ordinary Time / St. Ephrem", ref: "Matthew 5:13-16", verse: "Let your light shine before others.", summary: "You are the salt of the earth — but if salt loses its taste it is thrown out. You are the light of the world — a city on a hill cannot be hidden. Let your light shine so others glorify your heavenly Father." },
"06-10": { season: "Ordinary Time", title: "Wednesday — 10th Week of Ordinary Time", ref: "Matthew 5:17-19", verse: "I have come not to abolish the law but to fulfill it.", summary: "Jesus insists the Law and prophets remain entirely valid. Not a single letter will pass away. Whoever breaks the least commandment and teaches others to do so will be called least; whoever obeys and teaches will be great in the Kingdom." },
"06-11": { season: "Memorial", title: "St. Barnabas, Apostle", ref: "Matthew 10:7-13", verse: "As you go, make this proclamation: 'The Kingdom of heaven is at hand.'", summary: "Jesus sends the Twelve: preach that the Kingdom is at hand, heal the sick, raise the dead, cleanse lepers, drive out demons. You received without payment; give without payment. Greet every household with peace." },
"06-12": { season: "Ordinary Time", title: "Friday — 10th Week of Ordinary Time", ref: "Matthew 5:27-32", verse: "Everyone who looks at a woman with lust has already committed adultery with her in his heart.", summary: "Jesus deepens the commandment against adultery: sin begins in the heart. If your right eye causes you to sin, tear it out. It is better to lose one part than to have your whole body cast into Gehenna." },
"06-13": { season: "Memorial", title: "St. Anthony of Padua", ref: "Matthew 5:33-37", verse: "Let your 'Yes' mean 'Yes' and your 'No' mean 'No.'", summary: "Jesus forbids oaths: do not swear by heaven, earth, Jerusalem, or your own head. Let your yes mean yes and your no mean no. Anything more comes from the evil one." },
"06-14": { season: "Ordinary Time", title: "11th Sunday of Ordinary Time — Year C", ref: "Luke 7:36 — 8:3", verse: "Her many sins have been forgiven because she has shown great love.", summary: "A sinful woman bathes Jesus' feet with her tears and anoints them. The Pharisee Simon is scandalized. Jesus teaches through the parable of the two debtors: the greater the debt forgiven, the greater the love shown. He forgives and sends her in peace." },
"06-15": { season: "Ordinary Time", title: "Monday — 11th Week of Ordinary Time", ref: "Matthew 5:38-42", verse: "Turn the other cheek.", summary: "Jesus replaces the law of retaliation with radical non-violence: turn the other cheek, give your cloak too, walk the extra mile, give to whoever begs from you. This is the new way of God's Kingdom." },
"06-16": { season: "Ordinary Time", title: "Tuesday — 11th Week of Ordinary Time", ref: "Matthew 5:43-48", verse: "Love your enemies and pray for those who persecute you.", summary: "The highest commandment: love your enemies and pray for persecutors. God makes the sun rise on the bad and good alike. If you love only those who love you, what is special about that? Be perfect as your heavenly Father is perfect." },
"06-17": { season: "Ordinary Time", title: "Wednesday — 11th Week of Ordinary Time", ref: "Matthew 6:1-6, 16-18", verse: "Your Father who sees in secret will repay you.", summary: "Jesus teaches the three pillars of Jewish piety: almsgiving, prayer, and fasting. All three must be done in secret, for the Father who sees in secret, not for human praise." },
"06-18": { season: "Ordinary Time", title: "Thursday — 11th Week of Ordinary Time", ref: "Matthew 6:7-15", verse: "Our Father who art in heaven...", summary: "Jesus teaches the Lord's Prayer as the model of Christian prayer. Pray to the Father, seek his Kingdom, ask for daily bread, beg forgiveness as we forgive others, seek protection from the evil one." },
"06-19": { season: "Ordinary Time", title: "Friday — 11th Week of Ordinary Time / St. Romuald", ref: "Matthew 6:19-23", verse: "Where your treasure is, there also will your heart be.", summary: "Store treasures in heaven, not on earth where rust and moths destroy. The lamp of the body is the eye — if healthy, the whole body is full of light. If your eye is bad, your whole body is in darkness." },
"06-20": { season: "Ordinary Time", title: "Saturday — 11th Week of Ordinary Time", ref: "Matthew 6:24-34", verse: "Seek first the Kingdom of God, and all these things will be given you besides.", summary: "No one can serve two masters. Do not worry about your life — look at the birds and the lilies. Your heavenly Father knows your needs. Seek the Kingdom first, and everything else will be given to you." },
"06-21": { season: "Memorial", title: "St. Aloysius Gonzaga / 12th Sunday — Year C", ref: "Luke 9:18-24", verse: "Who do you say that I am? — The Christ of God.", summary: "Jesus asks who people say he is, then asks the disciples directly. Peter professes: The Christ of God. Jesus predicts his Passion. He calls all to deny themselves, take up their cross daily, and follow him. Whoever loses his life for his sake will save it." },
"06-22": { season: "Memorial", title: "Sts. Thomas More and John Fisher", ref: "Matthew 22:34-40", verse: "On these two commandments hang all the Law and the Prophets.", summary: "A lawyer tests Jesus: which commandment is greatest? Love God with all your heart, soul, and mind — this is the first and greatest. The second is like it: love your neighbor as yourself. All law and prophecy depend on these two." },
"06-23": { season: "Ordinary Time", title: "Tuesday — 12th Week of Ordinary Time", ref: "Matthew 7:6, 12-14", verse: "Enter through the narrow gate.", summary: "Do not throw what is sacred to dogs or pearls before swine. The Golden Rule: do to others what you want done to you. Enter through the narrow gate — the road to life is hard and few find it." },
"06-24": { season: "Solemnity", title: "Nativity of St. John the Baptist", ref: "Luke 1:57-66, 80", verse: "His name is John.", summary: "Elizabeth gives birth to a son. On the eighth day the people want to name him Zechariah after his father. Elizabeth insists: his name is John. Zechariah's mouth opens. The child grows and becomes strong in spirit in the desert." },
"06-25": { season: "Ordinary Time", title: "Thursday — 12th Week of Ordinary Time", ref: "Matthew 7:21-29", verse: "Not everyone who says to me, 'Lord, Lord,' will enter the Kingdom of heaven.", summary: "Not those who say Lord Lord but those who do the Father's will. Many will claim to have prophesied and performed miracles in his name, but he will declare he never knew them. Build on rock, not sand." },
"06-26": { season: "Ordinary Time", title: "Friday — 12th Week of Ordinary Time", ref: "Matthew 8:1-4", verse: "Lord, if you wish, you can make me clean.", summary: "A leper comes down from the mountain and begs Jesus: if you wish, you can make me clean. Jesus stretches out his hand, touches him, and says: I do will it. Be made clean. The leprosy is immediately healed." },
"06-27": { season: "Ordinary Time", title: "Saturday — 12th Week of Ordinary Time / St. Cyril of Alexandria", ref: "Matthew 8:5-17", verse: "Lord, I am not worthy to have you enter under my roof.", summary: "The centurion's faith: Lord, I am not worthy — just say the word. Jesus marvels at such faith and heals the servant at that moment. Jesus then heals Peter's mother-in-law and cures many at evening." },
"06-28": { season: "Memorial", title: "St. Irenaeus, Bishop and Martyr", ref: "Matthew 8:18-22", verse: "Follow me, and let the dead bury their dead.", summary: "A scribe offers to follow Jesus wherever he goes. Jesus says: the Son of Man has nowhere to lay his head. Another says: first let me bury my father. Jesus answers: follow me and let the dead bury their dead." },
"06-29": { season: "Solemnity", title: "Sts. Peter and Paul, Apostles", ref: "Matthew 16:13-19", verse: "You are Peter, and upon this rock I will build my Church.", summary: "Peter's confession at Caesarea Philippi: You are the Christ, the Son of the living God. Jesus declares Peter blessed by the Father. He renames him Rock and promises to build his Church on him — and the gates of the netherworld shall not prevail against it." },
"06-30": { season: "Ordinary Time", title: "Tuesday — 13th Week / First Martyrs of the Church of Rome", ref: "Matthew 8:23-27", verse: "Why are you terrified, O you of little faith?", summary: "A violent storm on the sea. The disciples cry out. Jesus rebukes the wind and the sea: there is great calm. He asks why they are afraid, O you of little faith. They marvel: what sort of man is this that wind and sea obey him?" },

// ==================== JULY ====================
"07-01": { season: "Ordinary Time", title: "Wednesday — 13th Week of Ordinary Time", ref: "Matthew 8:28-34", verse: "What have you to do with us, Son of God?", summary: "Jesus casts demons from two men in the Gerasene territory. The demons beg to enter a herd of swine — the swine rush into the sea. The whole town begs Jesus to leave their district." },
"07-02": { season: "Ordinary Time", title: "Thursday — 13th Week of Ordinary Time", ref: "Matthew 9:1-8", verse: "Courage, child, your sins are forgiven.", summary: "Jesus returns to Capernaum. He forgives the paralytic's sins, scandalizing the scribes. He then heals the man to show his authority over sin. The crowds glorify God who gave such authority to human beings." },
"07-03": { season: "Feast", title: "St. Thomas the Apostle", ref: "John 20:24-29", verse: "My Lord and my God!", summary: "Thomas was absent when Jesus first appeared. He refuses to believe without touching the wounds. A week later Jesus appears and invites Thomas to touch him. Thomas makes the greatest confession: My Lord and my God! Blessed are those who have not seen and yet believe." },
"07-04": { season: "Ordinary Time", title: "Saturday — 13th Week of Ordinary Time", ref: "Matthew 9:14-17", verse: "New wine into fresh wineskins.", summary: "John's disciples question fasting while Jesus' disciples do not. The wedding guests cannot fast while the bridegroom is with them. New cloth on old cloth; new wine in old wineskins. The new order of the Kingdom has arrived." },
"07-05": { season: "Ordinary Time", title: "14th Sunday of Ordinary Time — Year C", ref: "Luke 10:1-12, 17-20", verse: "The harvest is abundant but the laborers are few.", summary: "Jesus appoints seventy-two and sends them ahead in pairs. Pray for laborers. Go as lambs among wolves. The Kingdom of God is at hand. The seventy-two return with joy: even demons are subject to us in your name." },
"07-06": { season: "Ordinary Time", title: "Monday — 14th Week / St. Maria Goretti", ref: "Matthew 9:18-26", verse: "My daughter has just died, but come lay your hand on her and she will live.", summary: "Jairus begs Jesus to restore his daughter. A woman with hemorrhage touches the tassel of his cloak and is healed by her faith. Jesus reaches the house and raises the girl. The news spreads throughout the region." },
"07-07": { season: "Ordinary Time", title: "Tuesday — 14th Week of Ordinary Time", ref: "Matthew 9:32-38", verse: "The harvest is abundant but the laborers are few.", summary: "Jesus heals a mute demoniac. The Pharisees attribute it to the prince of demons. Jesus goes about all the towns, moved with pity for the crowds like sheep without a shepherd. He prays for laborers." },
"07-08": { season: "Ordinary Time", title: "Wednesday — 14th Week of Ordinary Time", ref: "Matthew 10:1-7", verse: "Go to the lost sheep of the house of Israel.", summary: "Jesus summons the Twelve and gives them authority over unclean spirits and illness. He names each apostle. He sends them to the lost sheep of Israel: proclaim that the Kingdom of heaven is at hand." },
"07-09": { season: "Memorial", title: "Sts. Augustine Zhao Rong and Companions", ref: "Matthew 10:16-23", verse: "You will be hated by all because of my name.", summary: "Jesus warns the apostles: I send you like sheep among wolves. You will be handed over and flogged. When they hand you over, do not worry — the Spirit of your Father will speak through you. Persevere to the end to be saved." },
"07-10": { season: "Ordinary Time", title: "Thursday — 14th Week of Ordinary Time", ref: "Matthew 10:7-15", verse: "Without cost you have received; without cost you are to give.", summary: "Go, cure the sick, raise the dead, cleanse lepers, drive out demons. Take no gold, silver, or sandals — the laborer deserves his keep. Shake the dust from your feet where not welcomed." },
"07-11": { season: "Memorial", title: "St. Benedict, Abbot", ref: "Matthew 19:27-29", verse: "Everyone who has given up everything for my name will receive a hundred times more.", summary: "Peter asks what reward awaits those who left everything. Jesus promises twelve thrones for the Twelve, and a hundredfold for all who left houses, family, or lands for his name — and eternal life." },
"07-12": { season: "Ordinary Time", title: "Saturday — 14th Week of Ordinary Time", ref: "Matthew 10:24-33", verse: "Do not be afraid of those who kill the body but cannot kill the soul.", summary: "The disciple is not above the teacher. Fear only the one who can destroy both body and soul. Even the hairs of your head are all counted. Whoever acknowledges Jesus before others will be acknowledged before the Father." },
"07-13": { season: "Ordinary Time", title: "15th Sunday of Ordinary Time — Year C", ref: "Luke 10:25-37", verse: "Which of these three was a neighbor to the man who fell in with robbers?", summary: "The Good Samaritan: a scholar of law asks who is his neighbor. A man is robbed and left for dead. Priest and Levite pass by. A Samaritan stops, tends to him, and pays for his care. Jesus commands: go and do likewise." },
"07-14": { season: "Ordinary Time", title: "Monday — 15th Week / St. Kateri Tekakwitha", ref: "Matthew 10:34 — 11:1", verse: "Whoever loses his life for my sake will find it.", summary: "Jesus did not come to bring peace but a sword. He warns of family divisions. Whoever loves father or mother more than Jesus is not worthy of him. Carrying the cross means following. Whoever receives a disciple receives Jesus." },
"07-15": { season: "Memorial", title: "St. Bonaventure", ref: "Matthew 11:20-24", verse: "Woe to you, Chorazin! Woe to you, Bethsaida!", summary: "Jesus reproaches the towns where most of his miracles were done because they did not repent. Chorazin and Bethsaida will be worse off than Tyre and Sidon on the day of judgment. Capernaum, lifted up, will be cast down to the netherworld." },
"07-16": { season: "Memorial", title: "Our Lady of Mount Carmel", ref: "Matthew 11:25-27", verse: "No one knows the Son except the Father, and no one knows the Father except the Son.", summary: "Jesus gives thanks to the Father for hiding these things from the wise and revealing them to the childlike. All has been handed over by the Father. No one knows the Father except the Son and those to whom the Son reveals him." },
"07-17": { season: "Ordinary Time", title: "Thursday — 15th Week of Ordinary Time", ref: "Matthew 11:28-30", verse: "Come to me, all you who labor and are burdened, and I will give you rest.", summary: "Jesus calls all who are weary and burdened. Take his yoke upon you, learn from him — for he is meek and humble of heart. His yoke is easy and his burden light." },
"07-18": { season: "Ordinary Time", title: "Friday — 15th Week of Ordinary Time", ref: "Matthew 12:1-8", verse: "The Son of Man is Lord of the sabbath.", summary: "The disciples pluck grain on the Sabbath. Jesus cites David eating the showbread and the Temple priests working on the Sabbath. Something greater than the Temple is here. God desires mercy, not sacrifice. The Son of Man is Lord of the Sabbath." },
"07-19": { season: "Ordinary Time", title: "Saturday — 15th Week of Ordinary Time", ref: "Matthew 12:14-21", verse: "He will not contend or cry out.", summary: "The Pharisees plot to destroy Jesus. He withdraws from there and heals many, ordering them not to make him known. Matthew cites Isaiah's servant prophecy: he will not cry out or break a bruised reed." },
"07-20": { season: "Ordinary Time", title: "16th Sunday of Ordinary Time — Year C", ref: "Luke 10:38-42", verse: "Mary has chosen the better part.", summary: "Martha and Mary: Martha is anxious and worried about many things in her hospitality. Mary sits at the Lord's feet listening. Jesus defends Mary: she has chosen the better part — it will not be taken from her." },
"07-21": { season: "Ordinary Time", title: "Monday — 16th Week / St. Lawrence of Brindisi", ref: "Matthew 12:38-42", verse: "Something greater than Jonah is here.", summary: "The scribes and Pharisees demand a sign. Jesus offers only the sign of Jonah: as Jonah was in the whale three days, so the Son of Man will be in the heart of the earth. The Queen of the South and the Ninevites will condemn this generation." },
"07-22": { season: "Feast", title: "St. Mary Magdalene", ref: "John 20:1-2, 11-18", verse: "I have seen the Lord!", summary: "Mary Magdalene is the first witness to the Resurrection. She weeps at the empty tomb. She sees two angels, then Jesus himself — at first thinking him the gardener. When Jesus calls her by name, she recognizes him and cries out: Rabboni! He sends her to announce the Resurrection." },
"07-23": { season: "Ordinary Time", title: "Wednesday — 16th Week / St. Bridget of Sweden", ref: "Matthew 13:1-9", verse: "Whoever has ears ought to hear.", summary: "The Parable of the Sower: seed on the path, rocky ground, thorns, and good soil, producing a hundred, sixty, and thirtyfold. The parable calls for attentive hearing of the Word of God." },
"07-24": { season: "Ordinary Time", title: "Thursday — 16th Week / St. Sharbel Makhluf", ref: "Matthew 13:10-17", verse: "Blessed are your eyes, because they see, and your ears, because they hear.", summary: "The disciples ask why Jesus teaches in parables. He explains: they have been granted to know the mysteries of the Kingdom; others have not. The disciples are blessed to see and hear what prophets longed to see." },
"07-25": { season: "Feast", title: "St. James the Apostle", ref: "Matthew 20:20-28", verse: "Whoever wishes to be great among you shall be your servant.", summary: "The mother of James and John asks for places of honor. Jesus says: can you drink the cup I am going to drink? They say yes. Jesus grants the cup but not the places. Greatness in the Kingdom means serving, as the Son of Man came to serve." },
"07-26": { season: "Memorial", title: "Sts. Joachim and Anne, Parents of Mary", ref: "Matthew 13:16-17", verse: "Blessed are your eyes, because they see.", summary: "Jesus pronounces the disciples blessed: many prophets and righteous people longed to see and hear what the disciples experience. Joachim and Anne raised the child who would bear the Savior — their faith bore the ultimate fruit." },
"07-27": { season: "Ordinary Time", title: "17th Sunday of Ordinary Time — Year C", ref: "Luke 11:1-13", verse: "Lord, teach us to pray.", summary: "A disciple asks Jesus to teach them to pray. Jesus gives the Our Father. He teaches persistence: the friend at midnight receives bread because of persistence. Ask, seek, knock. The Father gives good gifts — above all the Holy Spirit." },
"07-28": { season: "Ordinary Time", title: "Monday — 17th Week of Ordinary Time", ref: "Matthew 13:31-35", verse: "The Kingdom of heaven is like a mustard seed.", summary: "The mustard seed becomes the largest of shrubs — birds nest in its branches. The Kingdom is also like yeast mixed into dough until the whole batch is leavened. Jesus speaks only in parables to the crowds, fulfilling the prophet." },
"07-29": { season: "Memorial", title: "Sts. Martha, Mary and Lazarus", ref: "John 11:19-27", verse: "I am the resurrection and the life.", summary: "Martha meets Jesus on the road after Lazarus has died. She confesses: if you had been here my brother would not have died. Jesus declares: I am the resurrection and the life. Whoever believes in me will never die. Do you believe this? Martha confesses: You are the Christ." },
"07-30": { season: "Ordinary Time", title: "Wednesday — 17th Week / St. Peter Chrysologus", ref: "Matthew 13:44-46", verse: "He sells all that he has and buys that field.", summary: "The Parables of the Treasure and the Pearl: a man finds treasure hidden in a field and sells everything to buy it. A merchant finds a pearl of great price and sells all to buy it. The Kingdom of God is worth everything." },
"07-31": { season: "Memorial", title: "St. Ignatius of Loyola", ref: "Matthew 13:47-53", verse: "Every scribe trained for the Kingdom of heaven is like a householder who brings from his storeroom both the new and the old.", summary: "The parable of the net: the Kingdom is like a dragnet gathering all sorts of fish. At the end the bad are separated from the good. The scribe of the Kingdom draws from both old and new wisdom." },

// ==================== AUGUST ====================
"08-01": { season: "Ordinary Time", title: "Saturday — 17th Week / St. Alphonsus Liguori", ref: "Matthew 14:1-12", verse: "Herod had John arrested and put in prison.", summary: "Herod hears reports of Jesus and fears John the Baptist has risen. The account of John's martyrdom: imprisoned for reproving Herod's marriage, John is beheaded when the king makes a rash promise to Herodias's daughter." },
"08-02": { season: "Ordinary Time", title: "18th Sunday of Ordinary Time — Year C", ref: "Luke 12:13-21", verse: "One's life does not consist of possessions.", summary: "A man asks Jesus to settle an inheritance. Jesus refuses and warns against greed: life is not about possessions. The Parable of the Rich Fool: a man tears down barns to build bigger ones and says 'eat, drink, be merry' — but God demands his life that night. So it is with those who are rich for themselves but not toward God." },
"08-03": { season: "Ordinary Time", title: "Monday — 18th Week of Ordinary Time", ref: "Matthew 14:13-21", verse: "You give them some food yourselves.", summary: "After John's death, Jesus withdraws by boat. The crowds follow on foot. Jesus is moved with compassion and heals the sick. At evening the disciples want to send the crowds away, but Jesus feeds five thousand with five loaves and two fish." },
"08-04": { season: "Memorial", title: "St. John Vianney (Curé of Ars)", ref: "Matthew 14:22-36", verse: "Lord, save me!", summary: "Jesus walks on water and Peter attempts to do the same — but sinks in fear and cries: Lord, save me! Jesus catches him and they get into the boat; the wind ceases. Those in the boat worship him: Truly, you are the Son of God." },
"08-05": { season: "Ordinary Time", title: "Dedication of the Basilica of Mary Major", ref: "Luke 11:27-28", verse: "Rather, blessed are those who hear the word of God and observe it.", summary: "A woman calls out: blessed is the womb that carried you. Jesus deepens this: rather, blessed are those who hear the word of God and observe it. True discipleship is not biological proximity to Jesus but faithful obedience." },
"08-06": { season: "Feast", title: "Transfiguration of the Lord", ref: "Matthew 17:1-9", verse: "This is my beloved Son, with whom I am well pleased; listen to him.", summary: "On the mountain, Jesus is transfigured before Peter, James, and John. His face shines like the sun, his clothes become white as light. Moses and Elijah appear. The Father's voice speaks from the cloud: This is my beloved Son — listen to him." },
"08-07": { season: "Ordinary Time", title: "Friday — 18th Week / Sts. Sixtus II and Cajetan", ref: "Matthew 16:24-28", verse: "Whoever wishes to save his life will lose it.", summary: "Jesus calls all to take up their cross daily and follow him. Whoever wishes to save his life will lose it; whoever loses his life for Jesus' sake will find it. What profit is it to gain the world and lose one's soul?" },
"08-08": { season: "Memorial", title: "St. Dominic", ref: "Matthew 17:14-20", verse: "Nothing will be impossible for you.", summary: "The disciples cannot drive out a demon from an epileptic boy. Jesus calls them of little faith. After he expels the demon, he tells them: if you have faith the size of a mustard seed you can move mountains. Nothing will be impossible for you." },
"08-09": { season: "Ordinary Time", title: "19th Sunday of Ordinary Time — Year C / St. Teresa Benedicta", ref: "Luke 12:32-48", verse: "Be ready, for the Son of Man is coming at an unexpected hour.", summary: "Do not be afraid, little flock — the Father is pleased to give you the Kingdom. Sell your possessions and give alms. The parable of the vigilant servants: blessed the servants the master finds watching when he returns. Be ready, for the Son of Man comes at an unexpected hour." },
"08-10": { season: "Feast", title: "St. Lawrence, Deacon and Martyr", ref: "John 12:24-26", verse: "Unless a grain of wheat falls to the ground and dies, it remains a grain of wheat.", summary: "Jesus teaches: unless the grain of wheat falls into the earth and dies, it remains alone. But if it dies, it bears much fruit. Whoever hates his life in this world preserves it for eternal life. Where Jesus is, his servant will also be." },
"08-11": { season: "Memorial", title: "St. Clare", ref: "Matthew 19:23-30", verse: "What is impossible for men is possible for God.", summary: "Jesus says it is easier for a camel to pass through a needle's eye than for a rich person to enter the Kingdom. The disciples are astonished. Jesus says with God all things are possible. Peter's question leads to promises of reward for those who left everything." },
"08-12": { season: "Ordinary Time", title: "Wednesday — 19th Week / St. Jane Frances de Chantal", ref: "Matthew 18:15-20", verse: "Where two or three are gathered in my name, there am I in the midst of them.", summary: "Church discipline: correct a brother privately, then with witnesses, then before the Church. Whatever you bind or loose on earth will be bound or loosed in heaven. When two agree and ask the Father, it will be granted. Where two or three gather in his name, he is there." },
"08-13": { season: "Ordinary Time", title: "Thursday — 19th Week / Sts. Pontian and Hippolytus", ref: "Matthew 18:21 — 19:1", verse: "Not seven times but seventy-seven times.", summary: "Peter asks how often to forgive. Jesus answers seventy-seven times. The Parable of the Unforgiving Servant: forgiven a vast debt, he strangles a fellow servant over a small amount. The master is enraged and hands him over. So will the heavenly Father do unless we forgive from our hearts." },
"08-14": { season: "Memorial", title: "St. Maximilian Maria Kolbe", ref: "Matthew 17:22-23", verse: "They will kill him, but he will be raised on the third day.", summary: "Jesus predicts his Passion and Resurrection a second time in Galilee. The disciples are overwhelmed with grief. Saint Maximilian Kolbe exemplified this passage — giving his life in place of another and rising to glory." },
"08-15": { season: "Solemnity", title: "Assumption of the Blessed Virgin Mary", ref: "Luke 1:39-56", verse: "My soul proclaims the greatness of the Lord.", summary: "The Visitation. Mary greets Elizabeth; John leaps in the womb. Elizabeth calls Mary blessed. Mary sings the Magnificat: the Almighty has done great things for me. The Assumption is the fulfillment of Mary's Magnificat — God has exalted the humble." },
"08-16": { season: "Ordinary Time", title: "20th Sunday of Ordinary Time — Year C / St. Stephen of Hungary", ref: "Luke 12:49-53", verse: "I have come to set the earth on fire.", summary: "Jesus came to cast fire on the earth. He has a baptism of blood to undergo. He did not come to establish peace but rather division — households will be divided because of him. Following him may mean conflict even with family." },
"08-17": { season: "Ordinary Time", title: "Monday — 20th Week of Ordinary Time", ref: "Matthew 19:16-22", verse: "Go, sell what you have and give to the poor, and come, follow me.", summary: "The rich young man: what must I do to have eternal life? Keep the commandments. He has done all these. Jesus offers more: sell everything, give to the poor, follow me. The young man goes away sad, for he had many possessions." },
"08-18": { season: "Ordinary Time", title: "Tuesday — 20th Week of Ordinary Time", ref: "Matthew 19:23-30", verse: "With God all things are possible.", summary: "Jesus speaks of the difficulty for the rich. The disciples are astonished. Peter asks about their reward. Jesus promises the Twelve will sit on thrones judging Israel. Whoever left family or possessions will receive a hundredfold and inherit eternal life." },
"08-19": { season: "Ordinary Time", title: "Wednesday — 20th Week / St. John Eudes", ref: "Matthew 20:1-16", verse: "The last will be first, and the first will be last.", summary: "The Parable of the Workers in the Vineyard: all workers receive the same wage regardless of hours worked. Those hired first grumble, but the owner asks: are you envious because I am generous? The last will be first and the first will be last." },
"08-20": { season: "Memorial", title: "St. Bernard of Clairvaux", ref: "Matthew 20:17-28", verse: "Whoever wishes to be great must be your servant.", summary: "Jesus predicts the Passion in Jerusalem. The mother of James and John seeks honor for her sons. Jesus teaches servant leadership: whoever wishes to be great must serve. The Son of Man came not to be served but to give his life as a ransom for many." },
"08-21": { season: "Memorial", title: "St. Pius X", ref: "Matthew 22:34-40", verse: "You shall love the Lord your God with all your heart.", summary: "The scholar of the law tests Jesus: which commandment is greatest? Love God with all your heart, soul, and mind — this is the first. The second is like it: love your neighbor as yourself. All the Law and prophets depend on these two." },
"08-22": { season: "Memorial", title: "Queenship of Mary / 21st Sunday — Year C", ref: "Luke 13:22-30", verse: "Strive to enter through the narrow gate.", summary: "Someone asks if only a few will be saved. Jesus says strive to enter through the narrow gate — many will try and not succeed. When the master closes the door, those who call out will be told: I do not know where you are from. People will come from east and west to recline at the Kingdom table." },
"08-23": { season: "Ordinary Time", title: "Monday — 21st Week / St. Rose of Lima", ref: "Matthew 23:13-22", verse: "Woe to you, scribes and Pharisees, you hypocrites!", summary: "Jesus pronounces woes against the scribes and Pharisees. You lock the Kingdom against others and do not enter yourselves. You traverse sea and land for one convert and make him a child of Gehenna. Blind guides swearing by gold but neglecting justice." },
"08-24": { season: "Feast", title: "St. Bartholomew, Apostle", ref: "John 1:45-51", verse: "You will see the angels of God ascending and descending on the Son of Man.", summary: "Philip tells Nathanael they found the one Moses and the prophets wrote about — Jesus of Nazareth. Nathanael doubts: can anything good come from Nazareth? Jesus sees Nathanael and calls him a true Israelite without guile. Nathanael confesses: You are the Son of God." },
"08-25": { season: "Ordinary Time", title: "Wednesday — 21st Week / St. Louis", ref: "Matthew 23:27-32", verse: "You are like whitewashed tombs.", summary: "Jesus denounces the scribes and Pharisees: they appear clean on the outside but inside are full of dead men's bones and every impurity. They honor the prophets' tombs while being the children of those who killed the prophets." },
"08-26": { season: "Ordinary Time", title: "Thursday — 21st Week of Ordinary Time", ref: "Matthew 24:42-51", verse: "Be prepared, for you do not know what day your Lord will come.", summary: "The parable of the faithful and unfaithful servants. Be prepared because you don't know when the Lord will come. The servant found faithful when the master returns will be rewarded. The unfaithful servant will be punished with the hypocrites." },
"08-27": { season: "Memorial", title: "St. Monica", ref: "Matthew 25:1-13", verse: "Stay awake, for you know neither the day nor the hour.", summary: "The Parable of the Ten Virgins: five wise bring oil, five foolish do not. When the bridegroom comes at midnight, the foolish have no oil. The door is shut. Stay awake, for you know neither the day nor the hour." },
"08-28": { season: "Memorial", title: "St. Augustine of Hippo", ref: "Matthew 25:14-30", verse: "Well done, my good and faithful servant!", summary: "The Parable of the Talents: servants receive 5, 2, and 1 talent. The first two invest and double their money; the third buries his talent. The master praises the first two and condemns the fearful servant. To those who have, more will be given." },
"08-29": { season: "Memorial", title: "Martyrdom of St. John the Baptist", ref: "Mark 6:17-29", verse: "He was beheaded in prison.", summary: "Herod had imprisoned John for reproving his marriage to Herodias. At a banquet, Herodias's daughter dances and Herod rashly promises whatever she asks. She asks for John's head. John is beheaded in prison — the first of the great Christian martyrs." },
"08-30": { season: "Ordinary Time", title: "22nd Sunday of Ordinary Time — Year C", ref: "Luke 14:1, 7-14", verse: "Everyone who exalts himself will be humbled, but the one who humbles himself will be exalted.", summary: "At a Sabbath meal Jesus observes guests choosing places of honor. He teaches: take the lowest place, lest you be moved down before everyone. When you host, invite the poor, the crippled, the lame — those who cannot repay you. Your reward will come at the resurrection." },
"08-31": { season: "Ordinary Time", title: "Monday — 22nd Week of Ordinary Time", ref: "Luke 4:16-30", verse: "Today this Scripture passage is fulfilled in your hearing.", summary: "Jesus reads from Isaiah in the Nazareth synagogue: the Spirit of the Lord is upon me to bring good news to the poor. He declares it fulfilled. He reminds them of Elijah and Elisha helping Gentiles. The crowd tries to throw him off a cliff, but he passes through their midst." },

// ==================== SEPTEMBER ====================
"09-01": { season: "Ordinary Time", title: "Tuesday — 22nd Week of Ordinary Time", ref: "Luke 4:31-37", verse: "What is there about his word? He commands the unclean spirits with authority.", summary: "Jesus teaches in Capernaum on the Sabbath. A man with an unclean spirit cries out. Jesus rebukes the demon: be quiet and come out! It leaves without harming the man. The people are amazed at his authority." },
"09-02": { season: "Ordinary Time", title: "Wednesday — 22nd Week of Ordinary Time", ref: "Luke 4:38-44", verse: "I must proclaim the good news of the Kingdom of God.", summary: "Jesus heals Simon's mother-in-law. At sunset many sick are brought and healed. Early morning he goes to a deserted place. The crowds seek him. He says he must proclaim the Kingdom to other towns — that is his mission." },
"09-03": { season: "Memorial", title: "St. Gregory the Great, Pope and Doctor", ref: "Luke 5:1-11", verse: "Do not be afraid; from now on you will be catching men.", summary: "From Simon's boat Jesus teaches. He commands the miraculous catch. Simon falls at his knees: depart from me, Lord, for I am a sinful man. Jesus answers: do not be afraid; from now on you will be catching men. They leave everything and follow." },
"09-04": { season: "Ordinary Time", title: "Friday — 22nd Week of Ordinary Time", ref: "Luke 5:33-39", verse: "New wine must be poured into fresh wineskins.", summary: "Why don't Jesus' disciples fast? The bridegroom's guests cannot fast while he is present. The days will come when he is taken. New cloth on old garments tears; new wine in old skins bursts. New wine needs fresh wineskins." },
"09-05": { season: "Ordinary Time", title: "Saturday — 22nd Week of Ordinary Time", ref: "Luke 6:1-5", verse: "The Son of Man is lord of the sabbath.", summary: "The disciples pick grain on the Sabbath. The Pharisees object. Jesus cites David eating the bread of offering. The Son of Man is Lord of the Sabbath — the Sabbath exists for human flourishing, not to constrain the Son of God." },
"09-06": { season: "Ordinary Time", title: "23rd Sunday of Ordinary Time — Year C", ref: "Luke 14:25-33", verse: "Whoever does not carry his own cross and come after me cannot be my disciple.", summary: "Jesus addresses the crowds about the cost of discipleship: unless you hate father and mother, spouse and children, even your own life, you cannot be my disciple. Like a builder estimating cost or a king planning for war — count the cost before following." },
"09-07": { season: "Ordinary Time", title: "Monday — 23rd Week of Ordinary Time", ref: "Luke 6:6-11", verse: "Is it lawful to do good or to do evil on the sabbath?", summary: "In the synagogue on the Sabbath, Jesus heals a man with a withered hand. He challenges the scribes and Pharisees: is it lawful to do good or evil on the Sabbath? He heals the man. They are filled with fury." },
"09-08": { season: "Feast", title: "Nativity of the Blessed Virgin Mary", ref: "Matthew 1:1-16, 18-23", verse: "Behold, the virgin shall conceive and bear a son, and they shall name him Emmanuel.", summary: "The genealogy of Jesus from Abraham through David to Joseph. Matthew traces the messianic lineage. The birth of Mary begins the final chapter of salvation history. She is the dawn that preceded the Sun of Justice." },
"09-09": { season: "Memorial", title: "St. Peter Claver", ref: "Luke 6:20-26", verse: "Blessed are you who are poor, for the Kingdom of God is yours.", summary: "The Beatitudes of Luke: blessed are the poor, the hungry, those who weep, the persecuted. Woe to the rich, the satisfied, those who laugh. St. Peter Claver spent his life serving enslaved African people — the poorest of the poor." },
"09-10": { season: "Ordinary Time", title: "Thursday — 23rd Week of Ordinary Time", ref: "Luke 6:27-38", verse: "Be merciful, just as your Father is merciful.", summary: "Love your enemies; do good to those who hate you. Lend without expecting return. Be merciful as the Father is merciful. Stop judging and you will not be judged. Forgive and you will be forgiven. Give and it will be given to you." },
"09-11": { season: "Ordinary Time", title: "Friday — 23rd Week of Ordinary Time", ref: "Luke 6:39-42", verse: "Remove the wooden beam from your eye first.", summary: "Can the blind lead the blind? The disciple is not above the teacher. Why see the splinter in your brother's eye and not the beam in your own? Remove the beam from your own eye first, then you can help your brother." },
"09-12": { season: "Ordinary Time", title: "Saturday — 23rd Week / Most Holy Name of Mary", ref: "Luke 6:43-49", verse: "A good tree does not bear rotten fruit.", summary: "A good tree bears good fruit; a rotten tree rotten fruit. From the fullness of the heart the mouth speaks. The person who hears Jesus' words and acts on them is like a house built on rock — it withstands the flood. Without acting, it collapses." },
"09-13": { season: "Ordinary Time", title: "24th Sunday of Ordinary Time — Year C / St. John Chrysostom", ref: "Luke 15:1-32", verse: "There will be rejoicing among the angels of God over one repentant sinner.", summary: "Three parables of mercy: the Lost Sheep, the Lost Coin, and the Prodigal Son. God rejoices over every sinner who repents. The father of the Prodigal runs to meet his returning son — an image of the Father's boundless mercy." },
"09-14": { season: "Feast", title: "Exaltation of the Holy Cross", ref: "John 3:13-17", verse: "God so loved the world that he gave his only Son.", summary: "No one has gone up to heaven except the one who came from heaven — the Son of Man. As Moses lifted up the serpent, so the Son of Man must be lifted up. God so loved the world he gave his only Son. The cross is the throne of God's love." },
"09-15": { season: "Memorial", title: "Our Lady of Sorrows", ref: "John 19:25-27", verse: "Woman, behold your son. Behold your mother.", summary: "At the foot of the cross stood Mary the mother of Jesus, Mary of Clopas, and Mary Magdalene. Jesus sees his mother and the beloved disciple and entrusts them to each other. A sword pierces Mary's soul — and she becomes the mother of all the faithful." },
"09-16": { season: "Memorial", title: "Sts. Cornelius and Cyprian", ref: "Luke 8:1-3", verse: "He journeyed from one town and village to another, proclaiming the good news of the Kingdom of God.", summary: "Jesus journeys through towns with the Twelve and certain women who had been healed: Mary Magdalene, Joanna, Susanna and many others. These women provided for Jesus and the disciples out of their resources." },
"09-17": { season: "Memorial", title: "St. Robert Bellarmine / St. Hildegard of Bingen", ref: "Luke 8:4-15", verse: "The seed is the word of God.", summary: "Jesus tells the Parable of the Sower to a large crowd. He later explains it to the disciples: the seed is God's word. Rocky ground, thorns, and the path are obstacles. The good soil — those with a noble and generous heart — bear fruit through perseverance." },
"09-18": { season: "Ordinary Time", title: "Friday — 24th Week of Ordinary Time", ref: "Luke 8:16-18", verse: "Nothing is concealed that will not be revealed.", summary: "No one lights a lamp and conceals it — it is placed on a lampstand. Nothing is concealed that will not be revealed. Pay attention to how you hear: to the one who has, more will be given; from the one who has not, even what he has will be taken." },
"09-19": { season: "Memorial", title: "St. Januarius", ref: "Luke 8:19-21", verse: "My mother and my brothers are those who hear the word of God and act on it.", summary: "Jesus' mother and brothers come to see him but cannot reach him through the crowd. Jesus declares: my mother and my brothers are those who hear the word of God and act on it. True kinship with Jesus is discipleship." },
"09-20": { season: "Memorial", title: "Sts. Andrew Kim Tae-gon and Companions", ref: "Luke 9:1-6", verse: "He sent them to proclaim the Kingdom of God and to heal the sick.", summary: "Jesus summons the Twelve and gives them power and authority over all demons and to cure diseases. He sends them to proclaim the Kingdom and heal the sick, taking nothing for the journey. They go through the villages." },
"09-21": { season: "Feast", title: "St. Matthew, Apostle and Evangelist", ref: "Matthew 9:9-13", verse: "Those who are well do not need a physician, but the sick do.", summary: "Jesus sees Matthew sitting at the tax collector's booth and calls him: follow me. Matthew gets up and follows. At dinner with tax collectors and sinners, Pharisees object. Jesus says he came not for the righteous but to call sinners." },
"09-22": { season: "Ordinary Time", title: "26th Sunday of Ordinary Time — Year C", ref: "Luke 16:19-31", verse: "Between us and you a great chasm has been fixed.", summary: "The Rich Man and Lazarus: the beggar is carried to Abraham's bosom at death; the rich man suffers in the netherworld. The rich man begs for a warning to his brothers, but Abraham says they have Moses and the prophets — and even a resurrection would not convince those who do not listen." },
"09-23": { season: "Memorial", title: "St. Pius of Pietrelcina (Padre Pio)", ref: "Luke 9:18-22", verse: "The Son of Man must suffer greatly.", summary: "Jesus prays alone with his disciples. He asks who the crowds say he is. Then: but who do you say I am? Peter: the Christ of God. Jesus predicts his Passion: he must suffer, be rejected, be killed, and rise on the third day." },
"09-24": { season: "Ordinary Time", title: "Wednesday — 25th Week of Ordinary Time", ref: "Luke 9:1-6", verse: "He sent them to proclaim the Kingdom of God.", summary: "Jesus gives the Twelve power and authority and sends them on mission: proclaim the Kingdom, heal the sick, take nothing for the journey. Shake the dust from your feet where you are not welcomed. They depart and go through the villages." },
"09-25": { season: "Ordinary Time", title: "Thursday — 25th Week of Ordinary Time", ref: "Luke 9:7-9", verse: "Who then is this about whom I hear such things?", summary: "Herod hears about all that is happening and is perplexed. Some say John has been raised, others that Elijah or one of the prophets has appeared. Herod says: John I beheaded — who then is this? And he kept trying to see him." },
"09-26": { season: "Ordinary Time", title: "Sts. Cosmas and Damian / Friday 25th Week", ref: "Luke 9:18-22", verse: "You are the Christ of God.", summary: "Peter's confession: you are the Christ of God. Jesus predicts his Passion and commands silence. He must suffer greatly, be rejected by the elders, priests, and scribes, be killed, and rise on the third day." },
"09-27": { season: "Memorial", title: "St. Vincent de Paul", ref: "Luke 9:43-45", verse: "The Son of Man is to be handed over to men.", summary: "While all are amazed at God's greatness, Jesus tells his disciples: the Son of Man will be handed over. They did not understand — it was hidden from them. They were afraid to ask him about it." },
"09-28": { season: "Ordinary Time", title: "St. Wenceslaus / 26th Sunday — Year C", ref: "Luke 16:19-31", verse: "They have Moses and the prophets — let them listen to them.", summary: "The Rich Man and Lazarus. After death their roles are reversed. The rich man begs Abraham to send Lazarus with a warning to his brothers. Abraham answers: they have Moses and the prophets. Even one rising from the dead will not convince those who refuse to listen." },
"09-29": { season: "Feast", title: "Sts. Michael, Gabriel and Raphael, Archangels", ref: "John 1:47-51", verse: "You will see the angels of God ascending and descending on the Son of Man.", summary: "Jesus sees Nathanael approaching and calls him a true Israelite. Nathanael is astonished: where do you know me from? Jesus says he saw him under the fig tree. Nathanael confesses: Son of God, King of Israel! Jesus promises he will see greater things — angels ascending and descending on the Son of Man." },
"09-30": { season: "Memorial", title: "St. Jerome, Priest and Doctor of the Church", ref: "Luke 10:1-12", verse: "The harvest is abundant but the laborers are few.", summary: "Jesus appoints seventy-two disciples and sends them two by two ahead of him. Pray for laborers. Go as lambs among wolves. Whatever town you enter, cure the sick and say: the Kingdom of God is at hand. Shake the dust where not welcomed." },

// ==================== OCTOBER ====================
"10-01": { season: "Memorial", title: "St. Thérèse of the Child Jesus (Lisieux)", ref: "Matthew 18:1-5", verse: "Unless you turn and become like children, you will not enter the Kingdom of heaven.", summary: "The disciples ask who is greatest in the Kingdom. Jesus places a child among them: unless you become like children, you cannot enter. Whoever humbles himself like a child is greatest. Thérèse's Little Way is precisely this childlike simplicity." },
"10-02": { season: "Memorial", title: "Guardian Angels", ref: "Matthew 18:1-5, 10", verse: "Their angels in heaven always look upon the face of my heavenly Father.", summary: "The child is the model of Kingdom greatness. Do not despise the little ones — their angels always behold the Father's face. This is the Scriptural foundation for belief in Guardian Angels: each person is entrusted to an angelic protector." },
"10-03": { season: "Ordinary Time", title: "Saturday — 26th Week of Ordinary Time", ref: "Luke 10:17-24", verse: "Rejoice because your names are written in heaven.", summary: "The seventy-two return with joy: even demons are subject to us! Jesus says he saw Satan fall like lightning. He gives them authority over all the enemy's power. Rejoice not that spirits submit but that your names are written in heaven." },
"10-04": { season: "Memorial", title: "St. Francis of Assisi", ref: "Matthew 11:25-30", verse: "Come to me, all you who labor and are burdened.", summary: "Jesus thanks the Father for revealing his mysteries to the childlike. All has been given to him by the Father. Come to me all who are burdened — learn from my meekness and humility of heart. My yoke is easy and my burden light." },
"10-05": { season: "Ordinary Time", title: "Monday — 27th Week of Ordinary Time", ref: "Luke 10:25-37", verse: "Go and do likewise.", summary: "The Good Samaritan: a lawyer asks who is his neighbor. A man left half-dead on the road is ignored by priest and Levite but aided by a despised Samaritan, who goes above and beyond in care. Go and do likewise." },
"10-06": { season: "Memorial", title: "St. Bruno", ref: "Luke 10:38-42", verse: "Mary has chosen the better part.", summary: "Martha and Mary: Martha is anxious; Mary sits at Jesus' feet. Jesus says Martha is worried about many things, but only one is necessary. Mary chose the better part — listening at the feet of the Lord." },
"10-07": { season: "Memorial", title: "Our Lady of the Rosary", ref: "Luke 11:1-4", verse: "Lord, teach us to pray.", summary: "A disciple asks Jesus to teach them to pray, as John taught his disciples. Jesus gives them the Our Father: Father, hallowed be your name, your Kingdom come, give us daily bread, forgive our sins, save us from temptation. The Rosary meditates on the mysteries of salvation." },
"10-08": { season: "Ordinary Time", title: "Thursday — 27th Week of Ordinary Time", ref: "Luke 11:5-13", verse: "Ask and you will receive.", summary: "The parable of the friend at midnight — persistence wins bread. If you who are evil give good gifts to children, how much more will the Father give the Holy Spirit to those who ask him?" },
"10-09": { season: "Memorial", title: "Sts. Denis and Companions / St. John Henry Newman", ref: "Luke 11:15-26", verse: "If by the finger of God I cast out demons, the Kingdom of God has come upon you.", summary: "Jesus is accused of casting out demons by Beelzebul. He refutes this logically: a divided kingdom falls. He casts out demons by the finger of God — a sign the Kingdom is present. The stronger one has arrived and taken away the armor of the strong one." },
"10-10": { season: "Ordinary Time", title: "Saturday — 27th Week of Ordinary Time", ref: "Luke 11:27-28", verse: "Blessed are those who hear the word of God and observe it.", summary: "A woman cries out: blessed is the womb that carried you. Jesus deepens this: rather, blessed are those who hear the word of God and observe it. The Blessed Virgin embodies both — she bore Jesus and perfectly observed the word." },
"10-11": { season: "Ordinary Time", title: "28th Sunday of Ordinary Time — Year C", ref: "Luke 17:11-19", verse: "Stand up and go; your faith has saved you.", summary: "Ten lepers ask Jesus for help. He tells them to show themselves to the priests. As they go, they are cleansed. Only one returns to give thanks — and he is a Samaritan, a foreigner. Jesus asks: were not ten cleansed? Where are the other nine?" },
"10-12": { season: "Ordinary Time", title: "Monday — 28th Week of Ordinary Time", ref: "Luke 11:29-32", verse: "No sign will be given except the sign of Jonah.", summary: "The crowds seek a sign. Only the sign of Jonah will be given. The Queen of the South traveled far to hear Solomon's wisdom — something greater than Solomon is here. The Ninevites repented at Jonah's preaching — something greater than Jonah is here." },
"10-13": { season: "Ordinary Time", title: "Tuesday — 28th Week of Ordinary Time", ref: "Luke 11:37-41", verse: "Cleanse the inside and the outside will also be clean.", summary: "A Pharisee is amazed Jesus does not wash before dinner. Jesus rebukes external religion: you cleanse the outside of cup and dish but inside you are full of greed and wickedness. Give alms and everything will be clean for you." },
"10-14": { season: "Memorial", title: "St. Callistus I", ref: "Luke 11:42-46", verse: "You tithe mint and rue but neglect justice and the love of God.", summary: "Woes against the Pharisees: they tithe herbs but neglect justice and love of God. They love the best seats and public greetings. They are unmarked graves people walk over without knowing. They burden others with impossible loads." },
"10-15": { season: "Memorial", title: "St. Teresa of Ávila", ref: "Luke 11:47-54", verse: "You have taken away the key of knowledge.", summary: "Woes against scholars of the law: they honor the prophets' tombs while their ancestors killed the prophets. They have taken away the key of knowledge — they do not enter and prevent others from entering. They seek to trap Jesus in his speech." },
"10-16": { season: "Memorial", title: "St. Hedwig / St. Margaret Mary Alacoque", ref: "Luke 12:1-7", verse: "Do not be afraid of those who kill the body.", summary: "Jesus warns against hypocrisy: nothing concealed will remain hidden. What is whispered in darkness will be proclaimed. Do not fear those who kill the body. Five sparrows sold for two coins — not one is forgotten by God. You are worth more than many sparrows." },
"10-17": { season: "Memorial", title: "St. Ignatius of Antioch, Bishop and Martyr", ref: "Luke 12:8-12", verse: "The Holy Spirit will teach you at that moment what you should say.", summary: "Whoever acknowledges Jesus will be acknowledged before the angels; whoever denies him will be denied. Blasphemy against the Holy Spirit is unforgivable. When handed over, do not worry — the Holy Spirit will teach you what to say." },
"10-18": { season: "Feast", title: "St. Luke the Evangelist", ref: "Luke 10:1-9", verse: "The Kingdom of God is at hand.", summary: "Jesus appoints seventy-two and sends them ahead in pairs. The harvest is abundant but laborers are few. Go as lambs among wolves. Heal the sick in every town and announce: the Kingdom of God is at hand for you. Luke the physician and evangelist lived this mission." },
"10-19": { season: "Memorial", title: "Sts. John de Brébeuf and Isaac Jogues, North American Martyrs", ref: "Luke 12:39-48", verse: "Much will be required of the person entrusted with much.", summary: "Stay prepared: the Son of Man comes at an unexpected hour. The faithful steward is found at work when the master returns and is rewarded. The unfaithful servant will be cut off. Much will be required of those entrusted with much." },
"10-20": { season: "Ordinary Time", title: "Tuesday — 29th Week of Ordinary Time", ref: "Luke 12:35-38", verse: "Blessed are those servants whom the master finds vigilant on his arrival.", summary: "Keep your lamps on and your loins girded: be like servants waiting for the master to return from a wedding. When he arrives at whatever hour — midnight or dawn — and finds them vigilant, he will wait on them himself." },
"10-21": { season: "Ordinary Time", title: "Wednesday — 29th Week of Ordinary Time", ref: "Luke 12:39-48", verse: "Be prepared, for the Son of Man is coming at an unexpected hour.", summary: "The faithful steward is given charge of the household. But if the servant says the master is delayed and begins to mistreat others and get drunk, the master will arrive unexpectedly and punish him severely. Much is required of those given much." },
"10-22": { season: "Ordinary Time", title: "Thursday — 29th Week / St. John Paul II", ref: "Luke 12:49-53", verse: "I have come to set the earth on fire.", summary: "Jesus came to cast fire on earth — he longs for it to blaze. He has a baptism of suffering to undergo. He brings division, not peace — households will be divided because of him. Faithful discipleship can create conflict." },
"10-23": { season: "Memorial", title: "St. John of Capistrano", ref: "Luke 12:54-59", verse: "Why do you not judge for yourselves what is right?", summary: "The crowd reads weather signs but not the signs of the times. Why can't you judge what is right? Settle with your accuser before reaching the magistrate, lest you be thrown in prison." },
"10-24": { season: "Memorial", title: "St. Anthony Mary Claret", ref: "Luke 13:1-9", verse: "Unless you repent, you will all perish as they did!", summary: "Jesus dismisses the idea that tragedy indicates greater sinfulness. All must repent. The Parable of the Fig Tree: give it one more year of care and fertilizer. If it then bears no fruit, cut it down. A final call to conversion." },
"10-25": { season: "Ordinary Time", title: "30th Sunday of Ordinary Time — Year C", ref: "Luke 18:9-14", verse: "The one who humbles himself will be exalted.", summary: "The Pharisee and the Tax Collector: the Pharisee lists his virtues; the tax collector beats his breast and pleads for mercy. Only the tax collector goes home justified. Whoever exalts himself will be humbled; whoever humbles himself will be exalted." },
"10-26": { season: "Ordinary Time", title: "Monday — 30th Week of Ordinary Time", ref: "Luke 13:10-17", verse: "Woman, you are set free of your infirmity!", summary: "Jesus heals a woman bent double for eighteen years on the Sabbath. The synagogue leader protests. Jesus calls him a hypocrite: you untie your ox on the Sabbath to water it — was it not right to free this daughter of Abraham?" },
"10-27": { season: "Ordinary Time", title: "Tuesday — 30th Week of Ordinary Time", ref: "Luke 13:18-21", verse: "The Kingdom of God is like a mustard seed.", summary: "The mustard seed becomes a large tree. The Kingdom is like yeast that leavens the whole batch of dough. The Kingdom begins small, hidden, and unremarkable — and grows to transform everything." },
"10-28": { season: "Feast", title: "Sts. Simon and Jude, Apostles", ref: "Luke 6:12-16", verse: "When day came, he called his disciples to himself, and from them he chose Twelve, whom he also named Apostles.", summary: "Jesus goes to the mountain to pray and spends the night in prayer. At daybreak he calls his disciples and chooses the Twelve — including Simon called the Zealot and Judas Iscariot. These are the foundations of the Church." },
"10-29": { season: "Ordinary Time", title: "Thursday — 30th Week of Ordinary Time", ref: "Luke 13:31-35", verse: "Jerusalem, Jerusalem, you who kill the prophets!", summary: "Pharisees warn Jesus that Herod wants to kill him. Jesus calls Herod a fox and declares he must move on. He laments over Jerusalem: how often he wanted to gather her children as a hen gathers her chicks. Your house is abandoned to you." },
"10-30": { season: "Ordinary Time", title: "Friday — 30th Week of Ordinary Time", ref: "Luke 14:1-6", verse: "Is it lawful to cure on the sabbath or not?", summary: "At a Sabbath dinner with a leading Pharisee, a man with dropsy appears. Jesus asks the scholars and Pharisees: is it lawful to cure on the Sabbath? They are silent. He heals the man and asks: would not any of you pull a son or ox out of a cistern on the Sabbath?" },
"10-31": { season: "Ordinary Time", title: "Saturday — 30th Week of Ordinary Time", ref: "Luke 14:1, 7-11", verse: "Everyone who exalts himself will be humbled.", summary: "Jesus notices guests choosing places of honor at table. He teaches: take the lowest place, lest the host move you down before everyone. For everyone who exalts himself will be humbled, and the one who humbles himself will be exalted." },

// ==================== NOVEMBER ====================
"11-01": { season: "Solemnity", title: "All Saints", ref: "Matthew 5:1-12", verse: "Blessed are the pure in heart, for they will see God.", summary: "The Beatitudes: the program of life for all who seek sainthood. The poor in spirit, the mourning, the meek, those who hunger for righteousness, the merciful, the pure of heart, the peacemakers, the persecuted — these are the ones who inherit the Kingdom." },
"11-02": { season: "Commemoration", title: "All Souls (Commemoration of All the Faithful Departed)", ref: "John 6:37-40", verse: "Everyone who believes in him will have eternal life, and I will raise him up on the last day.", summary: "Jesus declares the Father's will: that he should not lose any of those given to him, but raise them all on the last day. Everyone who sees the Son and believes in him has eternal life. This is the hope of the Church for all the faithful departed." },
"11-03": { season: "Memorial", title: "St. Martin de Porres", ref: "Luke 14:12-14", verse: "Invite the poor, the crippled, the lame, the blind.", summary: "When you hold a lunch or dinner, do not invite those who can repay you. Invite the poor, the crippled, the lame, the blind. You will be repaid at the resurrection of the righteous. Martin de Porres lived this Gospel in Lima, Peru." },
"11-04": { season: "Memorial", title: "St. Charles Borromeo", ref: "Matthew 25:31-46", verse: "Whatever you did for one of the least brothers of mine, you did for me.", summary: "The Final Judgment on the corporal works of mercy. The King will say to those on his right: come, you who are blessed by my Father. For I was hungry and you gave me food. Whatever done to the least was done to Christ himself." },
"11-05": { season: "Ordinary Time", title: "Thursday — 31st Week of Ordinary Time", ref: "Luke 15:1-10", verse: "There is rejoicing among the angels of God over one repentant sinner.", summary: "Two parables of the lost: the lost sheep — the shepherd leaves the ninety-nine; the lost coin — the woman lights a lamp and sweeps the whole house. Both find what was lost and celebrate. Heaven rejoices over one sinner who repents." },
"11-06": { season: "Ordinary Time", title: "Friday — 31st Week of Ordinary Time", ref: "Luke 16:1-8", verse: "The children of this world are more prudent in dealing with their own generation than are the children of light.", summary: "The Parable of the Dishonest Steward: a dishonest steward, about to be dismissed, reduces debtors' bills to win friends. His master commends his prudence. Jesus applies: use worldly wealth to make friends so they may welcome you into eternal dwellings." },
"11-07": { season: "Ordinary Time", title: "Saturday — 31st Week of Ordinary Time", ref: "Luke 16:9-15", verse: "No servant can serve two masters.", summary: "Use dishonest wealth to make friends for eternal dwelling. Whoever is faithful in small things is faithful in great. You cannot serve God and mammon. The Pharisees deride Jesus. He says: what is of human esteem is an abomination before God." },
"11-08": { season: "Ordinary Time", title: "32nd Sunday of Ordinary Time — Year C", ref: "Luke 20:27-38", verse: "He is not God of the dead, but of the living, for to him all are alive.", summary: "The Sadducees pose a resurrection riddle about a woman with seven husbands. Jesus answers: in the resurrection they neither marry nor are given in marriage. God is not God of the dead but of the living — for to him all are alive." },
"11-09": { season: "Feast", title: "Dedication of the Lateran Basilica", ref: "John 2:13-22", verse: "Destroy this temple and in three days I will raise it up.", summary: "Jesus drives the merchants from the Temple. The Jews demand a sign. He says: destroy this temple and I will raise it in three days. He spoke of the temple of his body. After the Resurrection the disciples remembered and believed the Scripture and his word." },
"11-10": { season: "Memorial", title: "St. Leo the Great", ref: "Luke 17:7-10", verse: "We are unprofitable servants; we have done what we were obliged to do.", summary: "Who among you would thank a servant for doing his duty? After doing everything commanded, say: we are unprofitable servants. We have only done what we were obliged to do. Genuine discipleship is humble service without expectation of reward." },
"11-11": { season: "Memorial", title: "St. Martin of Tours", ref: "Luke 17:11-19", verse: "Were not ten made clean? Where are the other nine?", summary: "Ten lepers call out to Jesus. He sends them to the priests — they are healed on the way. Only one returns to give thanks, and he is a Samaritan. Jesus asks where the nine are and says to him: your faith has saved you." },
"11-12": { season: "Memorial", title: "St. Josaphat", ref: "Luke 17:20-25", verse: "The Kingdom of God is among you.", summary: "Asked when the Kingdom of God will come, Jesus says it cannot be observed. You will not see signs saying: here it is, or there. The Kingdom of God is among you. But first the Son of Man must suffer greatly and be rejected." },
"11-13": { season: "Memorial", title: "St. Frances Xavier Cabrini", ref: "Luke 17:26-37", verse: "Remember Lot's wife!", summary: "As in Noah's and Lot's days, the coming of the Son of Man will be sudden and unexpected. Remember Lot's wife — do not look back at what you are leaving. Whoever tries to preserve his life will lose it; whoever loses it will save it." },
"11-14": { season: "Ordinary Time", title: "Saturday — 32nd Week of Ordinary Time", ref: "Luke 18:1-8", verse: "Will not God then secure the rights of his chosen ones who call out to him?", summary: "The Parable of the Persistent Widow: a widow pesters an unjust judge until he grants her justice. If an unjust judge responds to persistence, how much more will God secure the rights of his chosen who call to him day and night?" },
"11-15": { season: "Memorial", title: "St. Albert the Great", ref: "Luke 18:1-8", verse: "Will the Son of Man find faith on earth when he comes?", summary: "The persistent widow wins justice. God will secure the rights of those who call on him — and quickly. But Jesus asks: when the Son of Man comes, will he find faith on earth? A searching question for every generation." },
"11-16": { season: "Memorial", title: "St. Margaret of Scotland / St. Gertrude", ref: "Luke 18:1-8", verse: "Pray always without becoming weary.", summary: "Jesus tells the parable to teach that it is necessary to pray always without becoming weary. God is the just judge who will act — unlike the unjust judge in the parable. Persistent, trustful prayer is the foundation of Christian life." },
"11-17": { season: "Memorial", title: "St. Elizabeth of Hungary", ref: "Luke 19:1-10", verse: "The Son of Man has come to seek and to save what was lost.", summary: "Zacchaeus the chief tax collector climbs a tree to see Jesus. Jesus invites himself to Zacchaeus's house. People grumble. Zacchaeus pledges half his goods to the poor and restitution to all he defrauded. Jesus declares: today salvation has come to this house. The Son of Man came to seek and save the lost." },
"11-18": { season: "Feast", title: "Dedication of the Basilicas of Sts. Peter and Paul / St. Rose Philippine Duchesne", ref: "Matthew 28:16-20", verse: "Go, therefore, and make disciples of all nations.", summary: "The Great Commission: the Risen Jesus has all authority in heaven and on earth. Go and make disciples of all nations, baptizing them in the name of the Trinity, teaching them everything he commanded. He will be with us all days until the end of the age." },
"11-19": { season: "Ordinary Time", title: "Thursday — 33rd Week of Ordinary Time", ref: "Luke 19:41-44", verse: "If this day you only knew what makes for peace!", summary: "Jesus weeps over Jerusalem as he approaches: if only you knew what makes for peace! The days will come when your enemies will encircle you, dash you and your children to the ground, and leave not one stone on another — because you did not recognize the time of your visitation." },
"11-20": { season: "Ordinary Time", title: "Friday — 33rd Week of Ordinary Time", ref: "Luke 19:45-48", verse: "My house shall be a house of prayer, but you have made it a den of thieves.", summary: "Jesus enters the Temple and drives out the merchants, citing Isaiah and Jeremiah: my house shall be a house of prayer but you have made it a den of thieves. Daily he teaches in the Temple. The chief priests seek to destroy him but cannot — the people hang on his words." },
"11-21": { season: "Memorial", title: "Presentation of the Blessed Virgin Mary", ref: "Luke 21:1-4", verse: "This poor widow put in more than all the rest.", summary: "Jesus observes the rich putting offerings in the treasury, then a poor widow putting in two small coins. He declares: she has put in more than all the others. They gave from their surplus; she gave from her poverty — her whole livelihood." },
"11-22": { season: "Memorial", title: "St. Cecilia, Virgin and Martyr", ref: "Luke 21:12-19", verse: "By your perseverance you will secure your lives.", summary: "Jesus warns of persecution: they will hand you over, imprison you, bring you before kings and governors. Do not prepare your defense — I will give you wisdom. You will be betrayed by those nearest you. Those who endure to the end will save their lives." },
"11-23": { season: "Ordinary Time", title: "St. Clement I / St. Columban / Monday 34th Week", ref: "Luke 21:1-4", verse: "She has offered her whole livelihood.", summary: "The widow's mite in the Temple treasury. The wealthy give from their abundance; she gives two small coins — her entire livelihood. True generosity is measured not by amount but by the love and sacrifice behind the giving." },
"11-24": { season: "Memorial", title: "Sts. Andrew Dung-Lac and Vietnamese Martyrs", ref: "Luke 21:5-11", verse: "Do not be terrified; for these things must happen first.", summary: "People admire the Temple. Jesus says: not one stone will be left on another. When? What sign? Jesus warns of false prophets, wars, insurrections, earthquakes, famines. Do not be terrified — these things must happen first, but the end does not immediately follow." },
"11-25": { season: "Ordinary Time", title: "Wednesday — 34th Week / St. Catherine of Alexandria", ref: "Luke 21:12-19", verse: "Not a hair on your head will be destroyed.", summary: "Before the end, they will lay hands on you and persecute you. You will be betrayed by family. You will be hated because of my name. By your perseverance you will secure your lives. Not a hair on your head will be destroyed." },
"11-26": { season: "Ordinary Time", title: "Thursday — 34th Week of Ordinary Time", ref: "Luke 21:20-28", verse: "Your redemption is at hand.", summary: "Jesus speaks of Jerusalem's destruction and the great tribulation. The Son of Man will come in a cloud with great power and glory. When these signs begin to happen, stand erect and raise your heads — your redemption is at hand." },
"11-27": { season: "Ordinary Time", title: "Friday — 34th Week of Ordinary Time", ref: "Luke 21:29-33", verse: "Heaven and earth will pass away, but my words will not pass away.", summary: "The parable of the fig tree: when it blossoms you know summer is near. When you see these signs, know the Kingdom of God is near. This generation will not pass away until all is accomplished. Heaven and earth will pass away but not my words." },
"11-28": { season: "Ordinary Time", title: "Saturday — 34th Week of Ordinary Time", ref: "Luke 21:34-36", verse: "Be vigilant at all times and pray that you have the strength to stand before the Son of Man.", summary: "Jesus warns: do not let your hearts become drowsy from carousing, drunkenness, and worldly anxiety. That day will catch you like a trap. Be vigilant at all times, praying for the strength to stand before the Son of Man." },
"11-29": { season: "Advent", title: "1st Sunday of Advent — Year A (2026)", ref: "Matthew 24:37-44", verse: "Stay awake! For you do not know on which day your Lord will come.", summary: "As it was in Noah's days — eating, drinking, oblivious — so will be the coming of the Son of Man. Two will be in a field; one taken, one left. Stay awake! You do not know which day your Lord comes. Be prepared." },
"11-30": { season: "Feast", title: "St. Andrew, Apostle", ref: "Matthew 4:18-22", verse: "Come after me, and I will make you fishers of men.", summary: "By the Sea of Galilee, Jesus calls Simon and his brother Andrew from their nets. Come after me — I will make you fishers of men. They immediately leave their nets. He calls James and John from their boat with their father Zebedee." },

// ==================== DECEMBER ====================
"12-01": { season: "Advent", title: "Monday — 1st Week of Advent", ref: "Matthew 8:5-11", verse: "I say to you, many will come from the east and the west.", summary: "The centurion's faith: Lord, I am not worthy — only say the word. Jesus marvels at such faith and heals the servant. Many will come from east and west and recline at table with Abraham, Isaac, and Jacob — but children of the Kingdom may be cast out." },
"12-02": { season: "Advent", title: "Tuesday — 1st Week of Advent", ref: "Luke 10:21-24", verse: "Blessed are the eyes that see what you see!", summary: "Jesus gives thanks that the Father revealed these things to the childlike. No one knows the Father except the Son. Blessed are the eyes that see what the disciples see — prophets and kings longed to see what you see." },
"12-03": { season: "Memorial", title: "St. Francis Xavier", ref: "Matthew 9:35 — 10:1, 5-8", verse: "Go to the lost sheep of the house of Israel.", summary: "Jesus goes through all the towns, moved with compassion for the crowds like sheep without a shepherd. He gives the Twelve authority and sends them: proclaim the Kingdom is at hand, heal the sick, raise the dead, cleanse lepers." },
"12-04": { season: "Advent", title: "Thursday — 1st Week of Advent / St. John of Damascus", ref: "Matthew 7:21, 24-27", verse: "Everyone who listens to these words of mine and acts on them will be like a wise man who built his house on rock.", summary: "Not everyone who says Lord Lord will enter the Kingdom — only those who do the Father's will. The wise man builds on rock; the foolish on sand. When the storm comes, only the house on rock stands." },
"12-05": { season: "Advent", title: "Friday — 1st Week of Advent", ref: "Matthew 9:27-31", verse: "Let it be done for you according to your faith.", summary: "Two blind men follow Jesus crying: Son of David, have pity on us! He touches their eyes and says: let it be done according to your faith. Their eyes are opened. He sternly warns them to tell no one — but they spread the news." },
"12-06": { season: "Advent", title: "Saturday — 1st Week of Advent / St. Nicholas", ref: "Matthew 9:35 — 10:1, 5-8", verse: "The harvest is abundant but the laborers are few.", summary: "Jesus is moved with compassion for the crowds like sheep without a shepherd. He tells the disciples to pray for laborers. Then he sends the Twelve with authority — proclaim, heal, raise, cleanse. Give freely what you have freely received." },
"12-07": { season: "Advent", title: "2nd Sunday of Advent — Year A (2026) / St. Ambrose", ref: "Matthew 3:1-12", verse: "Repent, for the Kingdom of heaven is at hand!", summary: "John the Baptist preaches in the Judean desert. The prophet of Isaiah: a voice crying in the wilderness, prepare the way of the Lord. He baptizes with water for repentance. The one coming after him is mightier — he will baptize with the Holy Spirit and fire." },
"12-08": { season: "Solemnity", title: "Immaculate Conception of the Blessed Virgin Mary", ref: "Luke 1:26-38", verse: "Hail, full of grace! The Lord is with you.", summary: "Gabriel's greeting to Mary: full of grace. Do not be afraid — you have found favor with God. You will conceive and bear a son named Jesus, Son of the Most High, who will reign forever. Mary asks how this can be. The Holy Spirit will come upon you. Nothing is impossible for God. Mary says: be it done to me according to your word." },
"12-09": { season: "Advent", title: "Wednesday — 2nd Week of Advent / St. Juan Diego", ref: "Matthew 11:28-30", verse: "Come to me, all you who labor and are burdened, and I will give you rest.", summary: "Jesus calls the weary: take my yoke and learn from me, for I am meek and humble of heart. You will find rest. My yoke is easy and my burden light. In Advent we come to him who comes to us, to find rest." },
"12-10": { season: "Advent", title: "Thursday — 2nd Week of Advent / Our Lady of Loreto", ref: "Matthew 11:11-15", verse: "Among those born of women there has been none greater than John the Baptist.", summary: "Jesus praises John: no one born of women is greater, yet the least in the Kingdom is greater than he. From John's time until now the Kingdom suffers violence. All the prophets and the law prophesied up to John — he is Elijah who was to come." },
"12-11": { season: "Advent", title: "Friday — 2nd Week of Advent / St. Damasus I", ref: "Matthew 11:16-19", verse: "Wisdom is vindicated by her works.", summary: "This generation is like children calling to each other: we played and you would not dance; we sang and you would not weep. John came neither eating nor drinking — they said he was possessed. The Son of Man came eating and drinking — a glutton and drunkard. Wisdom is vindicated by her works." },
"12-12": { season: "Memorial", title: "Our Lady of Guadalupe", ref: "Luke 1:39-47", verse: "Blessed are you who believed that what was spoken to you by the Lord would be fulfilled.", summary: "Mary visits Elizabeth. Elizabeth cries out: blessed are you among women! Blessed is the fruit of your womb! Blessed is she who believed the Lord's word would be fulfilled. Mary responds: my soul proclaims the greatness of the Lord." },
"12-13": { season: "Memorial", title: "St. Lucy, Virgin and Martyr", ref: "Matthew 11:28-30", verse: "I am meek and humble of heart.", summary: "Jesus calls all who are weary to come to him. He offers rest — not by removing burdens, but by bearing them together. His yoke is easy; his burden light. Lucy, bearing the light of faith in a dark world, embodied this promise." },
"12-14": { season: "Advent", title: "3rd Sunday of Advent (Gaudete) — Year A / St. John of the Cross", ref: "Matthew 11:2-11", verse: "Are you the one who is to come, or should we look for another?", summary: "John the Baptist sends disciples to Jesus: are you the one? Jesus answers: go tell John what you hear and see — the blind regain sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Blessed is the one who is not scandalized by me." },
"12-15": { season: "Advent", title: "Monday — 3rd Week of Advent", ref: "Matthew 21:23-27", verse: "Neither shall I tell you by whose authority I do these things.", summary: "The chief priests and elders question Jesus' authority. He poses a counter-question about John's baptism. When they refuse to answer, Jesus refuses to answer them. The refusal to acknowledge truth forfeits the right to receive it." },
"12-16": { season: "Advent", title: "Tuesday — 3rd Week of Advent", ref: "Matthew 21:28-32", verse: "Tax collectors and prostitutes are entering the Kingdom of God before you.", summary: "The parable of the two sons: one says no but does the father's will; the other says yes but does not. John came in righteousness and the tax collectors believed; the chief priests did not. Those who repent enter the Kingdom first." },
"12-17": { season: "Advent", title: "Wednesday — 3rd Week of Advent", ref: "Matthew 1:1-17", verse: "The book of the genealogy of Jesus Christ, son of David, son of Abraham.", summary: "The genealogy of Jesus Christ: from Abraham through David, through exile to Babylon, to Joseph the husband of Mary. This genealogy grounds Jesus in human history — the fulfillment of Israel's long journey toward the Messiah." },
"12-18": { season: "Advent", title: "Thursday — 3rd Week of Advent", ref: "Matthew 1:18-24", verse: "She will bear a son and you are to name him Jesus, because he will save his people from their sins.", summary: "Joseph finds Mary with child and plans to divorce her quietly. The angel of the Lord appears to him in a dream: Joseph, son of David, do not be afraid to take Mary as your wife. The child is of the Holy Spirit. He shall save his people from their sins — Emmanuel, God-with-us." },
"12-19": { season: "Advent", title: "Friday — 3rd Week of Advent", ref: "Luke 1:5-25", verse: "Do not be afraid, Zechariah, because your prayer has been heard.", summary: "Zechariah serves in the Temple when the angel Gabriel appears. Elizabeth will bear a son to be named John, who will be filled with the Holy Spirit from the womb. Zechariah doubts and is struck mute until the day these things occur." },
"12-20": { season: "Advent", title: "Saturday — 3rd Week of Advent", ref: "Luke 1:26-38", verse: "Nothing will be impossible for God.", summary: "Gabriel appears to Mary in Nazareth. She will conceive by the Holy Spirit and bear the Son of God. Even Elizabeth in her old age has conceived. Nothing is impossible for God. Mary says: I am the handmaid of the Lord — be it done to me according to your word." },
"12-21": { season: "Advent", title: "4th Sunday of Advent — Year A / St. Peter Canisius", ref: "Matthew 1:18-24", verse: "They shall name him Emmanuel, which means God is with us.", summary: "Joseph's dream: do not be afraid to take Mary as your wife. The child conceived by the Holy Spirit will save his people from their sins. This fulfills Isaiah's prophecy: a virgin shall be with child and name him Emmanuel — God with us." },
"12-22": { season: "Advent", title: "Monday — 4th Week of Advent", ref: "Luke 1:46-56", verse: "My soul proclaims the greatness of the Lord.", summary: "The Magnificat: Mary sings of God's mighty works — he has looked on his servant's humility, done great things, scattered the proud, lifted the lowly, filled the hungry, sent the rich away empty, and helped Israel his servant." },
"12-23": { season: "Advent", title: "Tuesday — 4th Week / St. John of Kanty", ref: "Luke 1:57-66", verse: "His name is John.", summary: "Elizabeth gives birth to a son. On the eighth day, against the family's wishes, she insists: his name is John. Zechariah writes: his name is John — and immediately his mouth opens. The neighbors are filled with awe: what will this child be?" },
"12-24": { season: "Advent", title: "Christmas Vigil Mass", ref: "Matthew 1:1-25", verse: "You are to name him Jesus.", summary: "The genealogy of Jesus Christ and the account of his birth. Joseph, descendant of David, learns Mary is with child by the Holy Spirit. The angel in the dream calls him to take Mary as his wife and name the child Jesus, who will save his people from their sins." },
"12-25": { season: "Solemnity", title: "Christmas — Nativity of the Lord (Mass at Dawn)", ref: "Luke 2:15-20", verse: "Let us go to Bethlehem to see this thing that has taken place.", summary: "The shepherds go in haste to Bethlehem and find Mary, Joseph, and the infant lying in the manger. They make known what was told them. All are amazed. Mary keeps all these things and reflects on them in her heart." },
"12-26": { season: "Feast", title: "St. Stephen, First Martyr", ref: "Matthew 10:17-22", verse: "You will be hated by all because of my name, but whoever endures to the end will be saved.", summary: "Jesus predicts persecution: you will be handed over to courts and flogged. You will be hated for my name. When they hand you over, the Spirit of the Father will speak through you. Stephen, the first martyr, fulfilled this on the day after Christmas." },
"12-27": { season: "Feast", title: "St. John, Apostle and Evangelist", ref: "John 20:2-8", verse: "He saw and believed.", summary: "Mary Magdalene reports the empty tomb to Simon Peter and the beloved disciple. They run — the beloved disciple arrives first, then Peter enters. The beloved disciple sees the burial cloths and believes. John, who leaned on Jesus' breast, is first to believe the Resurrection." },
"12-28": { season: "Feast", title: "Holy Innocents, Martyrs", ref: "Matthew 2:13-18", verse: "Herod ordered the massacre of all the boys in Bethlehem.", summary: "An angel warns Joseph in a dream: take the child and his mother and flee to Egypt. Herod, realizing he was deceived by the Magi, orders the massacre of all boys under two in Bethlehem. Rachel weeps for her children — they are no more." },
"12-29": { season: "Christmas", title: "5th Day within the Octave / St. Thomas Becket", ref: "Luke 2:22-35", verse: "This child is destined for the fall and rise of many in Israel.", summary: "The Presentation: Simeon takes the child and prays the Nunc Dimittis. He tells Mary: this child is a sign that will be contradicted. A sword will pierce your own soul. This reveals the hidden thoughts of many hearts." },
"12-30": { season: "Christmas", title: "Holy Family of Jesus, Mary and Joseph — Year C", ref: "Luke 2:41-52", verse: "Did you not know that I must be in my Father's house?", summary: "The Finding in the Temple: twelve-year-old Jesus stays behind in Jerusalem. After three days, Mary and Joseph find him in the Temple, listening to and questioning the teachers. He asks: did you not know I must be in my Father's house? He returns to Nazareth and is obedient to them." },
"12-31": { season: "Christmas", title: "7th Day within the Octave of Christmas / St. Sylvester I", ref: "John 1:1-18", verse: "The Word became flesh and made his dwelling among us.", summary: "The Prologue of John: In the beginning was the Word. All things came to be through him. Life and light for all people. John bore witness to the Light. To those who accepted him, he gave power to become children of God. The Word became flesh and dwelt among us, full of grace and truth." }

};

// Get gospel reading for a specific date
function getGospelForDate(month, day) {
  const key = String(month).padStart(2, '0') + '-' + String(day).padStart(2, '0');
  return GOSPEL_DATA[key] || null;
}

// Get all gospel readings for a month
function getGospelForMonth(month) {
  const monthStr = String(month).padStart(2, '0');
  return Object.entries(GOSPEL_DATA)
    .filter(([key]) => key.startsWith(monthStr + '-'))
    .map(([key, data]) => {
      const [m, d] = key.split('-');
      return { ...data, month: parseInt(m), day: parseInt(d), key };
    })
    .sort((a, b) => a.day - b.day);
}

